// ─── IMPORT 1 : MAP_PRODUIT_MARCHE ──────────────────────────────────────────
// Format A (EAN-based) : EAN | LABO | MARCHE | SOUS_MARCHE  → stocké dans condMapProduitMarche
//   Utilisé avec les boutons 2 et 3 (ventes LGPI) pour calculer les volumes par jointure EAN
// Format B (agrégé)    : SOUS_MARCHE | LABO | QTES_12M      → construit condMarchesVirtuels directement
function meqImporterMapProduitMarche() {
  var input = document.createElement('input');
  input.type = 'file'; input.accept = '.xlsx,.xls';
  input.onchange = function (e) {
    var file = e.target.files[0]; if (!file) return;
    var reader = new FileReader();
    reader.onload = function (ev) {
      try {
        var wb = XLSX.read(ev.target.result, { type: 'array' });

        // Chercher la feuille — noms connus en priorité, sinon scan (1ère ligne seulement)
        var NOMS_PRIORITAIRES = [
          'MAP_PRODUIT_MARCHE', 'MAP PRODUIT MARCHE',
          'MAPPING_PRODUIT_SOUS_MARCHE', 'MAP_ALL',
          'SOUS_MARCHES_LABOS', 'SOUS_MARCHE_LABO', 'SYNTH_SOUS_MARCHES_LABO'
        ];
        var sheetName = null;
        NOMS_PRIORITAIRES.forEach(function(n) {
          if (!sheetName && wb.SheetNames.indexOf(n) >= 0) sheetName = n;
        });
        if (!sheetName) {
          wb.SheetNames.forEach(function (n) {
            if (sheetName) return;
            var ws = wb.Sheets[n];
            if (!ws || !ws['!ref']) return;
            var rng = XLSX.utils.decode_range(ws['!ref']);
            rng.e.r = 0;
            var r1 = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '', range: rng });
            if (!r1.length) return;
            var hdrs = r1[0].map(function(h){ return String(h).toUpperCase().trim(); });
            var hasSM = hdrs.indexOf('SOUS_MARCHE') >= 0;
            if (hasSM && (hdrs.indexOf('EAN') >= 0 || hdrs.indexOf('LABO') >= 0)) sheetName = n;
          });
        }
        if (!sheetName) {
          alert('Feuille introuvable.\nFeuilles disponibles : ' + wb.SheetNames.slice(0,8).join(', ') + '…\n\nFichiers acceptés :\n• MOTEUR_DE_COMMANDE_UNIVERSEL_.xlsx (feuille MAP_PRODUIT_MARCHE)\n• Fichier agrégé SOUS_MARCHE | LABO | QTES_12M');
          return;
        }

        var ws = wb.Sheets[sheetName];
        var rows = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' });
        var hdrs = rows[0].map(function(h){ return String(h).toUpperCase().trim(); });

        function col(name) { return hdrs.indexOf(name); }
        var iEAN   = col('EAN');
        var iLABO  = col('LABO');
        var iMAR   = col('MARCHE');
        var iSM    = col('SOUS_MARCHE');
        var iQTES  = col('QTES_12M');
        var iLIB   = col('LIBELLE_SM');
        var iSTOCK = col('STOCK_TOTAL');

        // ── Format B : agrégé SOUS_MARCHE + LABO + QTES_12M (sans EAN) ──────
        if (iEAN < 0 && iSM >= 0 && iLABO >= 0 && iQTES >= 0) {
          var agg = {};
          rows.slice(1).forEach(function (r) {
            var sm   = String(r[iSM]   || '').trim();
            var labo = String(r[iLABO] || '').trim();
            if (!sm || !labo) return;
            var qtes  = parseFloat(String(r[iQTES]  || '0').replace(',','.')) || 0;
            var stock = iSTOCK >= 0 ? (parseFloat(String(r[iSTOCK] || '0').replace(',','.')) || 0) : 0;
            var lib   = iLIB >= 0 ? String(r[iLIB] || '').trim() : '';
            if (!agg[sm]) agg[sm] = { libelle: lib, produits: [] };
            if (lib && !agg[sm].libelle) agg[sm].libelle = lib;
            agg[sm].produits.push({ ean: '', labo_nom: labo, designation: labo,
              qtes_n: qtes, qtes_n1: 0, qtes_12m: qtes,
              ca_n: 0, ca_n1: 0, stock_total: stock, colisage: 1, statut_ref: 'agrégé' });
          });
          condMarchesVirtuels = {};
          Object.keys(agg).forEach(function(sm) {
            var d = agg[sm];
            d.produits.sort(function(a,b){ return b.qtes_n - a.qtes_n; });
            condMarchesVirtuels[sm] = {
              libelle: d.libelle || MEQ_LIBELLES[sm] || sm,
              segment: 'SOCLE', produits: d.produits
            };
          });
          try { localStorage.setItem('cond_marches_virtuels', JSON.stringify(condMarchesVirtuels)); } catch(e) {}
          meqInited = false; meqInit(); meqRender();
          alert('✅ Fichier agrégé importé (Format B)\n• ' + Object.keys(agg).length + ' sous-marchés\n• Feuille : ' + sheetName +
                '\n\nVolumes déjà inclus — pas besoin d\'importer les ventes LGPI.');
          return;
        }

        // ── Format A : EAN + LABO + SOUS_MARCHE ──────────────────────────────
        if (iEAN < 0 || iSM < 0) { alert('Colonnes EAN et SOUS_MARCHE introuvables dans la feuille ' + sheetName + '.'); return; }

        var nb = 0;
        rows.slice(1).forEach(function (r) {
          var ean = String(r[iEAN] || '').trim().replace(/\.0$/, '');
          var sm  = String(r[iSM]  || '').trim();
          if (!ean || !sm || sm === 'NON_CLASSIFIE') return;
          var iLIBMAP = col('LIBELLE');
          condMapProduitMarche[ean] = {
            labo:        iLABO >= 0   ? String(r[iLABO]   || '').trim() : '',
            marche:      iMAR  >= 0   ? String(r[iMAR]    || '').trim() : '',
            sous_marche: sm,
            libelle:     iLIBMAP >= 0 ? String(r[iLIBMAP] || '').trim() : ''
          };
          nb++;
        });

        try { localStorage.setItem('cond_map_produit_marche', JSON.stringify(condMapProduitMarche)); } catch(e) {}
        meqCalculerMarchesVirtuels();
        meqInited = false; meqInit(); meqRender();
        mapInited = true; if (typeof mapInitFiltres === 'function') mapInitFiltres(); if (typeof mapRender === 'function') mapRender();
        alert('✅ MAP_PRODUIT_MARCHE importé (Format A)\n• ' + nb + ' EANs mappés\n• Feuille : ' + sheetName +
              (Object.keys(condVentesOspharm).length
                ? '\n\n→ Marchés recalculés avec les ventes existantes.'
                : '\n\n→ Importez maintenant les ventes LGPI (bouton 2) pour calculer les volumes.'));
      } catch(err) { console.error(err); alert('Erreur : ' + err.message); }
    };
    reader.readAsArrayBuffer(file);
  };
  input.click();
}

// ─── IMPORT 2 : VENTES LGPI (N / N-1) ──────────────────────────────────────
// Format : Code EAN | Quantité | Quantité n-1 | CA TTC | CA TTC n-1 | Stocks quantité
function meqImporterVentesLGPI() {
  var input = document.createElement('input');
  input.type = 'file'; input.accept = '.xlsx,.xls';
  input.onchange = function (e) {
    var file = e.target.files[0]; if (!file) return;
    var reader = new FileReader();
    reader.onload = function (ev) {
      try {
        var wb = XLSX.read(ev.target.result, { type: 'array' });
        var sheetName = wb.SheetNames[0];
        var ws = wb.Sheets[sheetName];
        var rows = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' });
        var hdrs = rows[0].map(function(h){ return String(h).trim(); });

        function col(exact) {
          var i = hdrs.indexOf(exact);
          if (i >= 0) return i;
          // Recherche insensible casse
          var u = exact.toLowerCase();
          for (var j = 0; j < hdrs.length; j++) {
            if (hdrs[j].toLowerCase() === u) return j;
          }
          return -1;
        }

        var iEAN   = col('Code EAN');
        var iQN    = col('Quantité');
        var iQN1   = col('Quantité n-1');
        var iCAN   = col('CA TTC');
        var iCAN1  = col('CA TTC n-1');
        var iSTOCK = col('Stocks quantité');
        var iLIB   = col('Libellé produit');
        var iLABOC = col('Libellé laboratoire');

        if (iEAN < 0 || iQN < 0) { alert('Colonnes "Code EAN" et "Quantité" introuvables.\nVérifiez le fichier LGPI.'); return; }

        // ── Détection période et annualisation ──────────────────────────────
        var periodeN = meqDetecterPeriode(file.name);
        var coeffN   = 1;
        if (periodeN) {
          coeffN = periodeN.coeff;
        } else {
          var rep = prompt('Période non détectée dans le nom du fichier.\nCombien de mois couvre cet export ? (ex: 8)', '12');
          var moisSaisis = rep ? Math.max(1, parseFloat(rep) || 12) : 12;
          coeffN = Math.round(12 / moisSaisis * 100) / 100;
          periodeN = { debut: '?', fin: '?', nb_jours: Math.round(moisSaisis * 30.44), coeff: coeffN };
        }

        condVentesOspharm = {};
        var nb = 0;
        rows.slice(1).forEach(function (r) {
          var ean = String(r[iEAN] || '').trim().replace(/\.0$/, '');
          if (!ean) return;
          var qn   = parseFloat(String(r[iQN]  || '0').replace(',','.')) || 0;
          var qn1  = iQN1  >= 0 ? (parseFloat(String(r[iQN1]  || '0').replace(',','.')) || 0) : 0;
          var can  = iCAN  >= 0 ? (parseFloat(String(r[iCAN]  || '0').replace(',','.')) || 0) : 0;
          var can1 = iCAN1 >= 0 ? (parseFloat(String(r[iCAN1] || '0').replace(',','.')) || 0) : 0;
          var stk  = iSTOCK >= 0 ? (parseFloat(String(r[iSTOCK]|| '0').replace(',','.')) || 0) : 0;
          var lib  = iLIB  >= 0 ? String(r[iLIB]  || '').trim() : '';
          var labo = iLABOC >= 0 ? String(r[iLABOC] || '').trim() : '';
          var qn_r = Math.round(qn * coeffN);
          var stk_r = Math.round(stk);
          if (qn_r > 0 || stk_r > 0) {
            condVentesOspharm[ean] = {
              qtes_n:  qn_r,
              qtes_n1: Math.round(qn1 * coeffN),
              ca_n:    Math.round(can  * coeffN * 100) / 100,
              ca_n1:   Math.round(can1 * coeffN * 100) / 100,
              stock:   stk_r,
              lib:     lib ? lib.substring(0, 40) : ''
            };
          }
          nb++;
        });

        // Sauvegarder métadonnées
        condVentesMeta.N = { fichier: file.name, debut: periodeN.debut, fin: periodeN.fin,
                             nb_jours: periodeN.nb_jours, coeff: coeffN, annualise: coeffN !== 1 };
        // Ventes N gardées en mémoire uniquement (localStorage trop plein avec cond_labos)
        // Pas de setItem — condVentesOspharm reste accessible globalement pendant la session
        try { localStorage.setItem('cond_ventes_meta',    JSON.stringify(condVentesMeta));    } catch(e) {}

        var joined = meqCalculerMarchesVirtuels();
        meqInited = false; meqInit(); meqRender();
        mapInited = true; if (typeof mapInitFiltres === 'function') mapInitFiltres(); if (typeof mapRender === 'function') mapRender();

        var coeffMsg = coeffN !== 1
          ? '• Annualisation ×' + coeffN + ' (' + periodeN.nb_jours + ' j → projeté 12 mois)'
          : '• Période 12 mois — pas d\'annualisation';
        alert('✅ Ventes LGPI N importées\n• ' + nb + ' EANs' +
              (periodeN.debut !== '?' ? '\n• Période : ' + periodeN.debut + ' → ' + periodeN.fin : '') +
              '\n' + coeffMsg +
              (joined >= 0 ? '\n• ' + joined + ' EANs joints → ' + Object.keys(condMarchesVirtuels).length + ' sous-marchés' : '\n→ Importez MAP_PRODUIT_MARCHE pour calculer les marchés.'));
      } catch(err) { console.error(err); alert('Erreur : ' + err.message); }
    };
    reader.readAsArrayBuffer(file);
  };
  input.click();
}

// ─── IMPORT 3 : VENTES LGPI PÉRIODE N-1 (optionnel) ────────────────────────
// Même format que le fichier N — "Quantité" est lu comme qtes_n1
function meqImporterVentesLGPIN1() {
  var input = document.createElement('input');
  input.type = 'file'; input.accept = '.xlsx,.xls';
  input.onchange = function (e) {
    var file = e.target.files[0]; if (!file) return;
    var reader = new FileReader();
    reader.onload = function (ev) {
      try {
        var wb = XLSX.read(ev.target.result, { type: 'array' });
        var ws = wb.Sheets[wb.SheetNames[0]];
        var rows = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' });
        var hdrs = rows[0].map(function(h){ return String(h).trim(); });
        function col(exact) {
          var i = hdrs.indexOf(exact);
          if (i >= 0) return i;
          for (var j = 0; j < hdrs.length; j++) { if (hdrs[j].toLowerCase() === exact.toLowerCase()) return j; }
          return -1;
        }
        var iEAN  = col('Code EAN');
        var iQN   = col('Quantité');   // lu comme N-1
        var iCAN  = col('CA TTC');     // lu comme CA N-1
        if (iEAN < 0 || iQN < 0) { alert('Colonnes "Code EAN" et "Quantité" introuvables.'); return; }

        condVentesOspharmN1 = {};
        var nb = 0;
        rows.slice(1).forEach(function (r) {
          var ean = String(r[iEAN] || '').trim().replace(/\.0$/, '');
          if (!ean) return;
          condVentesOspharmN1[ean] = {
            qtes_n1: parseFloat(String(r[iQN]  || '0').replace(',','.')) || 0,
            ca_n1:   iCAN >= 0 ? (parseFloat(String(r[iCAN] || '0').replace(',','.')) || 0) : 0
          };
          nb++;
        });

        try { localStorage.setItem('cond_ventes_ospharm_n1', JSON.stringify(condVentesOspharmN1)); } catch(e) {}
        meqCalculerMarchesVirtuels();
        meqInited = false; meqInit(); meqRender();
        alert('✅ Ventes LGPI N-1 importées\n• ' + nb + ' EANs\n→ Marchés recalculés avec comparaison N/N-1.');
      } catch(err) { console.error(err); alert('Erreur : ' + err.message); }
    };
    reader.readAsArrayBuffer(file);
  };
  input.click();
}

// ─── CALCUL MARCHÉS VIRTUELS ────────────────────────────────────────────────
// Jointure condVentesOspharm × condMapProduitMarche → condMarchesVirtuels
function meqCalculerMarchesVirtuels() {
  if (!Object.keys(condMapProduitMarche).length) return -1;
  if (!Object.keys(condVentesOspharm).length)    return -1;

  var agg = {}; // { [sous_marche]: { [labo]: { qtes_n, qtes_n1, ca_n, ca_n1 } } }
  var smToMarche = {}; // { [sous_marche]: marche }
  var joined = 0;

  Object.keys(condVentesOspharm).forEach(function (ean) {
    var map = condMapProduitMarche[ean];
    if (!map) return;
    var sm   = map.sous_marche;
    var labo = map.labo;
    if (map.marche && !smToMarche[sm]) smToMarche[sm] = map.marche;
    var v    = condVentesOspharm[ean];
    if (!agg[sm]) agg[sm] = {};
    if (!agg[sm][labo]) agg[sm][labo] = { qtes_n: 0, qtes_n1: 0, ca_n: 0, ca_n1: 0 };
    agg[sm][labo].qtes_n  += v.qtes_n  || 0;
    // N-1 : fichier dédié prioritaire sur colonne n-1 du fichier N
    var vn1 = condVentesOspharmN1[ean];
    agg[sm][labo].qtes_n1 += vn1 ? (vn1.qtes_n1 || 0) : (v.qtes_n1 || 0);
    agg[sm][labo].ca_n    += v.ca_n    || 0;
    agg[sm][labo].ca_n1   += vn1 ? (vn1.ca_n1   || 0) : (v.ca_n1   || 0);
    joined++;
  });

  condMarchesVirtuels = {};
  Object.keys(agg).forEach(function (sm) {
    var produits = Object.keys(agg[sm]).map(function (labo) {
      var d = agg[sm][labo];
      return {
        ean: '', labo_nom: labo, designation: labo,
        qtes_n: d.qtes_n, qtes_n1: d.qtes_n1,
        qtes_12m: d.qtes_n,  // compat meqRender existant
        ca_n:  Math.round(d.ca_n  * 100) / 100,
        ca_n1: Math.round(d.ca_n1 * 100) / 100,
        colisage: 1, statut_ref: 'ventes LGPI'
      };
    }).sort(function (a, b) { return b.qtes_n - a.qtes_n; });

    condMarchesVirtuels[sm] = {
      libelle:  MEQ_LIBELLES[sm] || sm,
      marche:   smToMarche[sm]   || 'AUTRES',
      segment:  'SOCLE',
      produits: produits
    };
  });

  try { localStorage.setItem('cond_marches_virtuels', JSON.stringify(condMarchesVirtuels)); } catch(e) {}
  return joined;
}

// ─── DONNÉES DE DÉMONSTRATION ────────────────────────────────────────────────
var meqDataTest = [
  {
    id: 'PROB_1', libelle: 'Probiotiques (démo)', segment: 'SOCLE',
    produits: [
      { ean: '', labo_nom: 'NUTRI CO',     designation: 'Probiotiques NUTRI CO',  qtes_12m: 17, qtes_n: 17, qtes_n1: 0,  colisage: 1, statut_ref: 'démo' },
      { ean: '', labo_nom: 'PILEJE',       designation: 'Probiotiques PILEJE',    qtes_12m: 13, qtes_n: 13, qtes_n1: 0,  colisage: 1, statut_ref: 'démo' },
      { ean: '', labo_nom: 'BIOCODEX',     designation: 'Probiotiques BIOCODEX',  qtes_12m: 15, qtes_n: 15, qtes_n1: 0,  colisage: 1, statut_ref: 'démo' }
    ]
  }
];

// ─── MODE TOGGLE : sous-marché / labo ───────────────────────────────────────
var meqMode = 'sm'; // 'sm' | 'labo'

function meqSetMode(mode) {
  meqMode = mode;
  var btnSM   = document.getElementById('meq-mode-sm');
  var btnLabo = document.getElementById('meq-mode-labo');
  var fSM     = document.getElementById('meq-filters-sm');
  var fLabo   = document.getElementById('meq-filters-labo');
  if (!btnSM || !fSM) return;

  var activeStyle  = 'font-size:11px;padding:5px 14px;border-radius:var(--radius-sm);border:2px solid var(--accent);background:var(--accent);color:#fff;cursor:pointer;font-weight:600';
  var inactiveStyle = 'font-size:11px;padding:5px 14px;border-radius:var(--radius-sm);border:2px solid var(--border);background:#fff;color:var(--text-sec);cursor:pointer';

  if (mode === 'sm') {
    btnSM.style.cssText   = activeStyle;
    btnLabo.style.cssText = inactiveStyle;
    fSM.style.display   = 'flex';
    fLabo.style.display = 'none';
    meqRender();
  } else {
    btnSM.style.cssText   = inactiveStyle;
    btnLabo.style.cssText = activeStyle;
    fSM.style.display   = 'none';
    fLabo.style.display = 'flex';
    meqInitVueLabo();
    meqRenderVueLabo();
  }
}

// ─── INIT / GET DATA ─────────────────────────────────────────────────────────

// Retourne tous les sous-marchés sous forme plate, triés par volume N décroissant
function meqGetData() {
  if (Object.keys(condMarchesVirtuels).length) {
    return Object.keys(condMarchesVirtuels)
      .map(function (k) {
        var sm = condMarchesVirtuels[k];
        var totalN = (sm.produits || []).reduce(function (s, p) { return s + (p.qtes_n || 0); }, 0);
        return {
          id: k,
          libelle:  sm.libelle  || MEQ_LIBELLES[k] || k,
          marche:   sm.marche   || 'AUTRES',
          segment:  sm.segment  || 'SOCLE',
          produits: sm.produits || [],
          totalN:   totalN
        };
      })
      .sort(function (a, b) { return b.totalN - a.totalN });
  }
  return meqDataTest;
}

// Construit la liste des marchés distincts triés alphabétiquement
function meqGetMarches() {
  var set = {};
  meqGetData().forEach(function(sm) { set[sm.marche] = true; });
  return Object.keys(set).sort();
}

// Initialise les deux dropdowns en cascade
function meqInit() {
  var selM = document.getElementById('meq-select-marche');
  var selS = document.getElementById('meq-select');
  if (!selM || !selS) return;
  if (meqMode === 'labo') { meqInitVueLabo(); meqRenderVueLabo(); return; }

  var marches = meqGetMarches();
  selM.innerHTML = marches.map(function(m) {
    return '<option value="' + m + '">' + m + '</option>';
  }).join('');

  meqFiltrerSousMarches(marches[0] || '');
}

// Filtre le dropdown sous-marché selon le marché sélectionné
function meqFiltrerSousMarches(marcheId) {
  var selS = document.getElementById('meq-select');
  if (!selS) return;
  var data = meqGetData().filter(function(sm) { return sm.marche === marcheId; });
  selS.innerHTML = data.map(function(sm) {
    return '<option value="' + sm.id + '">' + sm.libelle + ' (' + sm.totalN + ' u.)</option>';
  }).join('');
  if (selS.options.length > 0) selS.selectedIndex = 0;
  meqRender();
}

// Appelé au changement du dropdown marché
function meqChangerMarche() {
  var selM = document.getElementById('meq-select-marche');
  if (selM) meqFiltrerSousMarches(selM.value);
}

function meqEstDonneesReelles() {
  return Object.keys(condMarchesVirtuels).length > 0;
}

// ─── HELPERS ─────────────────────────────────────────────────────────────────
function meqTrouverLaboParNom(nom) {
  if (!nom || typeof condLabos !== 'object') return null;
  var cible = nom.trim().toUpperCase();
  for (var id in condLabos) {
    if (!condLabos.hasOwnProperty(id)) continue;
    var n = (condLabos[id].nom || '').trim().toUpperCase();
    if (n === cible || n.indexOf(cible) >= 0 || cible.indexOf(n) >= 0) return condLabos[id];
  }
  return null;
}

function meqConditionsLabo(laboObj) {
  if (!laboObj) return null;
  var marches = laboObj.marches_negocies || [];
  var m = marches.find(function (mm) { return mm.palier_actif; }) || marches[0];
  return { remise: m ? (m.rem || 0) : 0, marcheLabel: m ? (m.label || m.marche_id || '') : '', franco: laboObj.francoPort || 0 };
}

// ─── RENDER ──────────────────────────────────────────────────────────────────
function meqRender() {
  var content = document.getElementById('meq-content');
  if (!content) return;
  var sel = document.getElementById('meq-select');
  if (!sel || !sel.value) { content.innerHTML = ''; return; }
  var data = meqGetData();
  var sm = data.find(function (x) { return x.id === sel.value; }) || data[0];
  if (!sm) { content.innerHTML = ''; return; }

  var totalN  = sm.produits.reduce(function (s, p) { return s + (p.qtes_n  || p.qtes_12m || 0); }, 0);
  var totalN1 = sm.produits.reduce(function (s, p) { return s + (p.qtes_n1 || 0); }, 0);
  var selectionne = meqSelections[sm.id] || null;
  var hasN1 = totalN1 > 0;

  var sourceMap  = Object.keys(condMapProduitMarche).length;
  var sourceVent = Object.keys(condVentesOspharm).length;
  var metaN = condVentesMeta && condVentesMeta.N ? condVentesMeta.N : null;
  var annualBadge = (metaN && metaN.annualise)
    ? ' <span style="font-size:10px;padding:2px 7px;background:#e8f4fd;color:#1a56db;border-radius:4px">×' + metaN.coeff + ' annualisé (' + metaN.debut + '→' + metaN.fin + ')</span>'
    : (metaN ? ' <span style="font-size:10px;padding:2px 7px;background:#f0f0f0;color:#666;border-radius:4px">12 mois</span>' : '');
  var badgeSrc = meqEstDonneesReelles()
    ? '<span style="font-size:10px;padding:2px 7px;background:#d4edda;color:#155724;border-radius:4px;margin-left:8px">✓ Ventes LGPI réelles</span>' + annualBadge
    : '<span style="font-size:10px;padding:2px 7px;background:#fff3cd;color:#856404;border-radius:4px;margin-left:8px">⚠ Données de démo</span>';

  // Résumé marché
  var evoTotal = (hasN1 && totalN1 > 0) ? ((totalN - totalN1) / totalN1 * 100).toFixed(0) : null;
  var evoTotalHtml = evoTotal !== null
    ? ' · Évolution <b style="color:' + (evoTotal >= 0 ? '#155724' : '#721c24') + '">' + (evoTotal >= 0 ? '+' : '') + evoTotal + '%</b>'
    : '';

  var rows = sm.produits.map(function (p) {
    var laboObj = meqTrouverLaboParNom(p.labo_nom);
    var cond = meqConditionsLabo(laboObj);
    var qn  = p.qtes_n  || p.qtes_12m || 0;
    var qn1 = p.qtes_n1 || 0;
    var part = totalN > 0 ? (qn / totalN * 100).toFixed(0) : '0';
    var evo  = (hasN1 && qn1 > 0) ? ((qn - qn1) / qn1 * 100).toFixed(0) : null;
    var evoHtml = evo !== null
      ? '<span style="color:' + (evo >= 0 ? '#155724' : '#721c24') + ';font-weight:600">' + (evo >= 0 ? '▲' : '▼') + Math.abs(evo) + '%</span>'
      : '<span style="color:var(--text-ter)">—</span>';
    var estSelectionne = selectionne === p.labo_nom;
    var condHtml = cond
      ? 'Remise <b>' + cond.remise + '%</b>' + (cond.marcheLabel ? ' (' + cond.marcheLabel + ')' : '') + ' · Franco <b>' + cond.franco + '€</b>'
      : '<span style="color:var(--text-ter)">—</span>';

    return '<tr style="' + (estSelectionne ? 'background:var(--accent-bg)' : '') + '">' +
      '<td style="padding:6px 8px;font-weight:600">' + p.labo_nom + '</td>' +
      '<td style="padding:6px 8px;text-align:right;font-weight:600">' + qn + '</td>' +
      (hasN1 ? '<td style="padding:6px 8px;text-align:right;color:var(--text-sec)">' + (qn1 || '—') + '</td>' : '') +
      (hasN1 ? '<td style="padding:6px 8px;text-align:center">' + evoHtml + '</td>' : '') +
      '<td style="padding:6px 8px;text-align:right">' + part + '%</td>' +
      '<td style="padding:6px 8px;font-size:11px">' + condHtml + '</td>' +
      '<td style="padding:6px 8px;text-align:center">' +
        '<button type="button" onclick="meqChoisir(\'' + sm.id + '\',\'' + p.labo_nom.replace(/'/g, "\\'") + '\')" ' +
        'style="font-size:11px;padding:4px 10px;border-radius:var(--radius-sm);border:1px solid var(--accent);' +
        'background:' + (estSelectionne ? 'var(--accent)' : '#fff') + ';color:' + (estSelectionne ? '#fff' : 'var(--accent-text)') + ';cursor:pointer;white-space:nowrap">' +
        (estSelectionne ? '✓ Retenu' : 'Retenir') + '</button>' +
      '</td></tr>';
  }).join('');

  // ── Ligne total ─────────────────────────────────────────────────────────
  var evoTotal2 = (hasN1 && totalN1 > 0) ? ((totalN - totalN1) / totalN1 * 100).toFixed(0) : null;
  var totalRowHtml =
    '<tr style="border-top:2px solid var(--border);font-weight:700;background:var(--bg-alt,#f8f9fa)">' +
    '<td style="padding:6px 8px">TOTAL MARCHÉ</td>' +
    '<td style="padding:6px 8px;text-align:right">' + totalN + '</td>' +
    (hasN1 ? '<td style="padding:6px 8px;text-align:right">' + totalN1 + '</td>' : '') +
    (hasN1 ? '<td style="padding:6px 8px;text-align:center">' +
      (evoTotal2 !== null ? '<span style="color:' + (evoTotal2 >= 0 ? '#155724' : '#721c24') + '">' + (evoTotal2 >= 0 ? '▲' : '▼') + Math.abs(evoTotal2) + '%</span>' : '—') +
    '</td>' : '') +
    '<td style="padding:6px 8px;text-align:right">100%</td>' +
    '<td colspan="2"></td>' +
    '</tr>';

  // ── Tableau produits (niveau EAN) ─────────────────────────────────────────
  var prodRows = [];
  if (Object.keys(condVentesOspharm).length) {
    Object.keys(condVentesOspharm).forEach(function(ean) {
      var map = condMapProduitMarche[ean];
      if (!map || map.sous_marche !== sm.id) return;
      var v = condVentesOspharm[ean];
      var vn1 = condVentesOspharmN1[ean];
      var qn  = v.qtes_n  || 0;
      var qn1 = vn1 ? (vn1.qtes_n1 || 0) : (v.qtes_n1 || 0);
      var evo = (hasN1 && qn1 > 0) ? ((qn - qn1) / qn1 * 100).toFixed(0) : null;
      var evoH = evo !== null
        ? '<span style="color:' + (evo >= 0 ? '#155724' : '#721c24') + '">' + (evo >= 0 ? '▲' : '▼') + Math.abs(evo) + '%</span>'
        : '<span style="color:var(--text-ter)">—</span>';
      var partP = totalN > 0 ? (qn / totalN * 100).toFixed(0) : '0';
      // Chercher libellé dans condLabos (toutes familles)
      var _libCL = '';
      if (!_libCL) { Object.values(condLabos).some(function(l){ return (l.produits||[]).some(function(p){ if(p.ean===ean && p.nom){ _libCL=p.nom; return true; } return false; }); }); }
      var lib = (_libCL || v.lib || v.libelle || ean).substring(0, 55);
      var laboNom = map.labo || v.labo_lgpi || '';
      prodRows.push({ qn: qn, html:
        '<tr>' +
        '<td style="padding:5px 8px;font-size:11px">' + lib + '</td>' +
        '<td style="padding:5px 8px;font-size:11px;color:var(--text-sec)">' + laboNom + '</td>' +
        '<td style="padding:5px 8px;text-align:right;font-weight:600">' + qn + '</td>' +
        (hasN1 ? '<td style="padding:5px 8px;text-align:right;color:var(--text-sec)">' + (qn1 || '—') + '</td>' : '') +
        (hasN1 ? '<td style="padding:5px 8px;text-align:center">' + evoH + '</td>' : '') +
        '<td style="padding:5px 8px;text-align:right">' + partP + '%</td>' +
        '</tr>'
      });
    });
    prodRows.sort(function(a,b){ return b.qn - a.qn; });
  }

  var tableauProduits = prodRows.length
    ? '<div class="card" style="margin-top:12px">' +
      '<p class="card-title" style="font-size:13px">Détail produits — ' + sm.libelle + '</p>' +
      '<table style="width:100%;border-collapse:collapse;font-size:12px">' +
      '<thead><tr style="border-bottom:2px solid var(--border)">' +
      '<th style="text-align:left;padding:5px 8px">Produit</th>' +
      '<th style="text-align:left;padding:5px 8px">Labo</th>' +
      '<th style="text-align:right;padding:5px 8px">Qtés N</th>' +
      (hasN1 ? '<th style="text-align:right;padding:5px 8px">Qtés N-1</th>' : '') +
      (hasN1 ? '<th style="text-align:center;padding:5px 8px">Évol.</th>' : '') +
      '<th style="text-align:right;padding:5px 8px">Part</th>' +
      '</tr></thead><tbody>' + prodRows.map(function(r){ return r.html; }).join('') + '</tbody></table>' +
      '</div>'
    : '';

  content.innerHTML =
    '<div class="card">' +
    '<p class="card-title">' + sm.libelle + badgeSrc + '</p>' +
    '<p style="font-size:11px;color:var(--text-sec);margin:0 0 10px 0">Marché total N : <b>' + totalN + '</b> unités' +
    (hasN1 ? ' · N-1 : <b>' + totalN1 + '</b>' : '') + evoTotalHtml + '</p>' +
    '<table style="width:100%;border-collapse:collapse;font-size:12px">' +
    '<thead><tr style="border-bottom:2px solid var(--border)">' +
    '<th style="text-align:left;padding:6px 8px">Labo</th>' +
    '<th style="text-align:right;padding:6px 8px">Qtés N</th>' +
    (hasN1 ? '<th style="text-align:right;padding:6px 8px">Qtés N-1</th>' : '') +
    (hasN1 ? '<th style="text-align:center;padding:6px 8px">Évol.</th>' : '') +
    '<th style="text-align:right;padding:6px 8px">Part</th>' +
    '<th style="text-align:left;padding:6px 8px">Conditions</th>' +
    '<th></th>' +
    '</tr></thead><tbody>' + rows + totalRowHtml + '</tbody></table>' +
    (selectionne ? '<p style="font-size:11px;color:var(--text-sec);margin-top:8px">Retenu : <b>' + selectionne + '</b> <button type="button" onclick="meqChoisir(\'' + sm.id + '\',null)" style="font-size:10px;padding:2px 6px;border:none;background:none;color:var(--danger);cursor:pointer">annuler</button></p>' : '') +
    '</div>' + tableauProduits;
}

function meqChoisir(smId, laboNom) {
  if (laboNom) meqSelections[smId] = laboNom; else delete meqSelections[smId];
  try { localStorage.setItem('meq_selections', JSON.stringify(meqSelections)); } catch (e) {}
  meqRender();
}

// ─── VUE PAR LABO ────────────────────────────────────────────────────────────

// Retourne la liste des labos présents dans condMarchesVirtuels, triés alphabétiquement
function meqGetLabos() {
  var set = {};
  Object.keys(condMarchesVirtuels).forEach(function(smId) {
    (condMarchesVirtuels[smId].produits || []).forEach(function(p) {
      if (p.labo_nom) set[p.labo_nom] = true;
    });
  });
  return Object.keys(set).sort();
}

// Initialise le dropdown labo
function meqInitVueLabo() {
  var sel = document.getElementById('meq-select-labo');
  if (!sel) return;
  var labos = meqGetLabos();
  sel.innerHTML = '<option value="">— Choisir un labo —</option>' +
    labos.map(function(l) { return '<option value="' + l + '">' + l + '</option>'; }).join('');
}

// Render vue labo : position dans tous les marchés + priorité de commande
function meqRenderVueLabo() {
  var content = document.getElementById('meq-content');
  if (!content) return;
  var sel = document.getElementById('meq-select-labo');
  var laboNom = sel ? sel.value : '';
  if (!laboNom) { content.innerHTML = '<div class="card"><p style="color:var(--text-ter);font-size:12px">Sélectionnez un labo pour voir sa position dans les marchés.</p></div>'; return; }

  // Collecter tous les sous-marchés où ce labo est présent
  var lignes = [];
  Object.keys(condMarchesVirtuels).forEach(function(smId) {
    var smData = condMarchesVirtuels[smId];
    var produits = smData.produits || [];
    var laboEntry = produits.find(function(p) { return p.labo_nom === laboNom; });
    if (!laboEntry) return;

    var totalN  = produits.reduce(function(s,p){ return s+(p.qtes_n||0); }, 0);
    var totalN1 = produits.reduce(function(s,p){ return s+(p.qtes_n1||0); }, 0);
    var rang = produits.filter(function(p){ return (p.qtes_n||0) > (laboEntry.qtes_n||0); }).length + 1;
    var part = totalN > 0 ? (laboEntry.qtes_n||0) / totalN * 100 : 0;
    var evo  = (laboEntry.qtes_n1||0) > 0 ? ((laboEntry.qtes_n||0) - (laboEntry.qtes_n1||0)) / (laboEntry.qtes_n1||0) * 100 : null;
    var evoMarcheTot = totalN1 > 0 ? (totalN - totalN1) / totalN1 * 100 : null;

    // CA depuis condVentesOspharm (somme des EANs du labo dans ce SM)
    var caN = 0;
    Object.keys(condVentesOspharm).forEach(function(ean) {
      var m = condMapProduitMarche[ean];
      if (m && m.sous_marche === smId && m.labo === laboNom) caN += condVentesOspharm[ean].ca_n || 0;
    });

    lignes.push({
      smId:    smId,
      libelle: smData.libelle || smId,
      marche:  smData.marche  || '—',
      qtes_n:  laboEntry.qtes_n  || 0,
      qtes_n1: laboEntry.qtes_n1 || 0,
      ca_n:    Math.round(caN),
      evo:     evo,
      evoMarche: evoMarcheTot,
      rang:    rang,
      nbLabos: produits.length,
      totalN:  totalN,
      part:    part
    });
  });

  if (!lignes.length) {
    content.innerHTML = '<div class="card"><p style="color:var(--text-ter);font-size:12px">Aucun marché trouvé pour ce labo. Vérifiez que MAP_PRODUIT_MARCHE et les ventes LGPI sont importés.</p></div>';
    return;
  }

  // ── Score de priorité : volume N desc, bonus évolution plafonné (max +50%, N-1≥5) ──
  lignes.sort(function(a, b) {
    var bonusA = (a.evo !== null && a.evo > 0 && a.qtes_n1 >= 5) ? 1 + Math.min(a.evo, 50) / 100 : 1;
    var bonusB = (b.evo !== null && b.evo > 0 && b.qtes_n1 >= 5) ? 1 + Math.min(b.evo, 50) / 100 : 1;
    var scoreA = a.qtes_n * bonusA;
    var scoreB = b.qtes_n * bonusB;
    if (Math.abs(scoreB - scoreA) > 0.01) return scoreB - scoreA;
    return b.ca_n - a.ca_n; // tiebreak : CA
  });

  var hasN1 = lignes.some(function(l){ return l.qtes_n1 > 0; });

  var rows = lignes.map(function(l, i) {
    var prio = i + 1;
    var prioBadge = prio <= 3
      ? '<span style="display:inline-block;width:22px;height:22px;line-height:22px;text-align:center;border-radius:50%;background:' + (['#2D5F8A','#5B9BD5','#A8C8E8'][prio-1]) + ';color:#fff;font-size:10px;font-weight:700">' + prio + '</span>'
      : '<span style="color:var(--text-ter);font-size:11px">' + prio + '</span>';

    var evoH = l.evo !== null
      ? '<span style="color:' + (l.evo >= 0 ? '#155724' : '#721c24') + ';font-weight:600">' + (l.evo >= 0 ? '▲' : '▼') + Math.abs(l.evo.toFixed(0)) + '%</span>'
      : '—';

    var rangBadge = l.rang === 1
      ? '<span style="color:#b8860b;font-weight:700">🥇 ' + l.rang + '/' + l.nbLabos + '</span>'
      : l.rang === 2
        ? '<span style="color:#666;font-weight:700">🥈 ' + l.rang + '/' + l.nbLabos + '</span>'
        : l.rang <= Math.ceil(l.nbLabos / 2)
          ? '<span style="color:var(--text-sec)">' + l.rang + '/' + l.nbLabos + '</span>'
          : '<span style="color:var(--accent);font-size:10px" title="Potentiel de gain PDM">⚡ ' + l.rang + '/' + l.nbLabos + '</span>';

    var oppBadge = (l.rang >= 3 && l.part < 20 && l.totalN > 50)
      ? ' <span style="font-size:9px;background:#fff3cd;color:#856404;padding:1px 5px;border-radius:3px">opportunité</span>'
      : '';

    return '<tr>' +
      '<td style="padding:7px 8px;text-align:center">' + prioBadge + '</td>' +
      '<td style="padding:7px 8px;font-size:11px;color:var(--text-sec)">' + l.marche + '</td>' +
      '<td style="padding:7px 8px;font-weight:600">' + l.libelle + oppBadge + '</td>' +
      '<td style="padding:7px 8px;text-align:right;font-weight:700">' + l.qtes_n + '</td>' +
      (hasN1 ? '<td style="padding:7px 8px;text-align:right;color:var(--text-sec)">' + (l.qtes_n1 || '—') + '</td>' : '') +
      (hasN1 ? '<td style="padding:7px 8px;text-align:center">' + evoH + '</td>' : '') +
      '<td style="padding:7px 8px;text-align:right">' + l.part.toFixed(0) + '%</td>' +
      '<td style="padding:7px 8px;text-align:right;font-size:11px">' + (l.ca_n > 0 ? l.ca_n.toLocaleString('fr-FR') + ' €' : '—') + '</td>' +
      '<td style="padding:7px 8px;text-align:center">' + rangBadge + '</td>' +
      '</tr>';
  }).join('');

  var totalVolume = lignes.reduce(function(s,l){ return s+l.qtes_n; }, 0);
  var totalCA = lignes.reduce(function(s,l){ return s+l.ca_n; }, 0);

  // ── 3e tableau : positions dominantes (rang 1, 2, 3) groupées par marché ──
  var top3 = lignes.filter(function(l){ return l.rang <= 3; });

  // Grouper par marché
  var marcheGroups = {};
  top3.forEach(function(l) {
    if (!marcheGroups[l.marche]) marcheGroups[l.marche] = [];
    marcheGroups[l.marche].push(l);
  });

  var top3Html = '';
  if (top3.length) {
    var marcheRows = Object.keys(marcheGroups).sort().map(function(marche, mi) {
      var sms = marcheGroups[marche];
      var totN = sms.reduce(function(s,l){ return s+l.qtes_n; }, 0);
      var nOr = sms.filter(function(l){ return l.rang===1; }).length;
      var nAr = sms.filter(function(l){ return l.rang===2; }).length;
      var nBr = sms.filter(function(l){ return l.rang===3; }).length;
      var mid = 'top3m' + mi;
      var badgesRes = (nOr ? '🥇×' + nOr + ' ' : '') + (nAr ? '🥈×' + nAr + ' ' : '') + (nBr ? '🥉×' + nBr : '');

      var smRows = sms.map(function(l) {
        var medaille = l.rang===1 ? '🥇' : l.rang===2 ? '🥈' : '🥉';
        var evoH = l.evo !== null
          ? '<span style="color:' + (l.evo>=0?'#155724':'#721c24') + '">' + (l.evo>=0?'▲':'▼') + Math.abs(l.evo.toFixed(0)) + '%</span>'
          : '—';
        return '<tr class="' + mid + '-rows" style="display:none;background:#fafbfc">' +
          '<td style="padding:5px 8px 5px 28px;font-size:11px">' + medaille + ' ' + l.libelle + '</td>' +
          '<td style="padding:5px 8px;text-align:center;font-size:11px">' + l.rang + '/' + l.nbLabos + '</td>' +
          '<td style="padding:5px 8px;text-align:right;font-weight:600">' + l.qtes_n + '</td>' +
          '<td style="padding:5px 8px;text-align:right">' + l.part.toFixed(0) + '%</td>' +
          '<td style="padding:5px 8px;text-align:center">' + evoH + '</td>' +
          '<td style="padding:5px 8px;text-align:right;font-size:11px">' + (l.ca_n>0?l.ca_n.toLocaleString('fr-FR')+' €':'—') + '</td>' +
          '</tr>';
      }).join('');

      return '<tr style="cursor:pointer;border-top:1px solid var(--border)" data-mid="' + mid + '" onclick="meqToggleTop3(this.dataset.mid, this)">' +
        '<td style="padding:8px;font-size:11px">▶</td>' +
        '<td style="padding:8px;font-weight:600">' + marche + '</td>' +
        '<td style="padding:8px;font-size:11px;color:var(--text-sec)">' + sms.length + ' sous-marché' + (sms.length>1?'s':'') + ' · ' + badgesRes + '</td>' +
        '<td style="padding:8px;text-align:right;font-weight:600">' + totN + '</td>' +
        '<td colspan="3"></td>' +
        '</tr>' + smRows;
    }).join('');

    top3Html = '<div class="card" style="margin-top:12px">' +
      '<p class="card-title" style="font-size:13px">🏆 Positions dominantes (rang 1, 2, 3) — ' + laboNom + '</p>' +
      '<p style="font-size:11px;color:var(--text-sec);margin:0 0 10px 0">' + top3.length + ' sous-marché' + (top3.length>1?'s':'') + ' où ' + laboNom + ' est dans le top 3 · Cliquer sur un marché pour développer</p>' +
      '<table style="width:100%;border-collapse:collapse;font-size:12px">' +
      '<thead><tr style="border-bottom:2px solid var(--border)">' +
      '<th style="width:24px"></th>' +
      '<th style="text-align:left;padding:8px">Marché</th>' +
      '<th style="text-align:left;padding:8px">Sous-marchés</th>' +
      '<th style="text-align:right;padding:8px">Qtés N</th>' +
      '<th style="text-align:center;padding:8px">Rang</th>' +
      '<th style="text-align:right;padding:8px">PDM</th>' +
      '<th style="text-align:right;padding:8px">CA N</th>' +
      '</tr></thead><tbody>' + marcheRows + '</tbody></table></div>';
  } else {
    top3Html = '<div class="card" style="margin-top:12px"><p style="font-size:11px;color:var(--text-ter)">Aucune position top 3 pour ce labo.</p></div>';
  }

  var metaNL = condVentesMeta && condVentesMeta.N ? condVentesMeta.N : null;
  var annualNoteLabo = metaNL
    ? '<span style="font-size:10px;padding:2px 7px;border-radius:4px;margin-left:8px;' + (metaNL.annualise ? 'background:#e8f4fd;color:#1a56db' : 'background:#f0f0f0;color:#666') + '">' + (metaNL.annualise ? '×' + metaNL.coeff + ' annualisé (' + metaNL.debut + '→' + metaNL.fin + ')' : '12 mois') + '</span>'
    : '';
  content.innerHTML =
    '<div class="card">' +
    '<p class="card-title">' + laboNom + annualNoteLabo + ' — Position dans ' + lignes.length + ' sous-marché' + (lignes.length > 1 ? 's' : '') + '</p>' +
    '<p style="font-size:11px;color:var(--text-sec);margin:0 0 10px 0">Volume total N : <b>' + totalVolume + '</b> unités · CA N : <b>' + totalCA.toLocaleString('fr-FR') + ' €</b>' +
    ' · Tri : volume N × évolution (plafond +50%, min N-1≥5) → CA</p>' +
    '<table style="width:100%;border-collapse:collapse;font-size:12px">' +
    '<thead><tr style="border-bottom:2px solid var(--border)">' +
    '<th style="text-align:center;padding:7px 8px">Priorité</th>' +
    '<th style="text-align:left;padding:7px 8px">Marché</th>' +
    '<th style="text-align:left;padding:7px 8px">Sous-marché</th>' +
    '<th style="text-align:right;padding:7px 8px">Qtés N</th>' +
    (hasN1 ? '<th style="text-align:right;padding:7px 8px">Qtés N-1</th>' : '') +
    (hasN1 ? '<th style="text-align:center;padding:7px 8px">Évol.</th>' : '') +
    '<th style="text-align:right;padding:7px 8px">PDM</th>' +
    '<th style="text-align:right;padding:7px 8px">CA N</th>' +
    '<th style="text-align:center;padding:7px 8px">Rang</th>' +
    '</tr></thead><tbody>' + rows + '</tbody>' +
    '<tfoot><tr style="border-top:2px solid var(--border);font-weight:700;background:var(--bg-alt,#f8f9fa)">' +
    '<td colspan="3" style="padding:7px 8px">TOTAL</td>' +
    '<td style="padding:7px 8px;text-align:right">' + totalVolume + '</td>' +
    (hasN1 ? '<td colspan="2"></td>' : '') +
    '<td></td>' +
    '<td style="padding:7px 8px;text-align:right">' + totalCA.toLocaleString('fr-FR') + ' €</td>' +
    '<td></td>' +
    '</tr></tfoot>' +
    '</table>' +
    '<p style="font-size:10px;color:var(--text-ter);margin-top:8px">⚡ = rang ≥ 3, PDM &lt; 20%, marché &gt; 50 u. → potentiel de gain · Bonus évolution plafonné à +50% (min N-1 ≥ 5)</p>' +
    '</div>' + top3Html;
}

// Toggle accordéon positions dominantes
function meqToggleTop3(mid, trEl) {
  var rows = document.querySelectorAll('.' + mid + '-rows');
  var open = rows.length > 0 && rows[0].style.display !== 'none';
  rows.forEach(function(r){ r.style.display = open ? 'none' : ''; });
  var arrow = trEl.querySelector('td:first-child');
  if (arrow) arrow.textContent = open ? '▶' : '▼';
}


// ═══════════════════════════════════════════════════════════════════════════
// ONGLET MAP PRODUITS — CRUD sur condMapProduitMarche
// ═══════════════════════════════════════════════════════════════════════════

var mapInited = false;
var mapEditEan = null;      // EAN en cours d'édition inline
var mapFilterMarche = '';   // filtre marché actif
var mapFilterSM     = '';   // filtre sous-marché actif

function mapInit() {
  var inp = document.getElementById('map-search');
  if (inp) inp.value = '';
  mapFilterMarche = '';
  mapFilterSM = '';
  mapInitFiltres();
  mapRender();
}

// Libellé d'un EAN : depuis MAP puis depuis ventes LGPI
function mapLibelle(ean) {
  var m = condMapProduitMarche[ean];
  if (m && m.libelle) return m.libelle;
  var v = condVentesOspharm[ean];
  return v && v.libelle ? v.libelle : '';
}

// Filtre + limite résultats (texte libre + marché + sous-marché)
function mapGetFiltered(q) {
  q = (q || '').toLowerCase().trim();
  var keys = Object.keys(condMapProduitMarche);
  var total = keys.length;

  var filtered = keys.filter(function(ean) {
    var m = condMapProduitMarche[ean];
    // Filtre marché
    if (mapFilterMarche && (m.marche || '') !== mapFilterMarche) return false;
    // Filtre sous-marché
    if (mapFilterSM && (m.sous_marche || '') !== mapFilterSM) return false;
    // Filtre texte libre
    if (q) {
      var lib = mapLibelle(ean).toLowerCase();
      return ean.indexOf(q) >= 0 ||
             lib.indexOf(q) >= 0 ||
             (m.labo || '').toLowerCase().indexOf(q) >= 0 ||
             (m.sous_marche || '').toLowerCase().indexOf(q) >= 0 ||
             (m.marche || '').toLowerCase().indexOf(q) >= 0;
    }
    return true;
  });

  var limit = (mapFilterMarche || mapFilterSM || q) ? 500 : 60;
  return { entries: filtered.slice(0, limit), total: total, filtered: filtered.length };
}

// Initialise les dropdowns marché et sous-marché à partir du MAP chargé
function mapInitFiltres() {
  var marches = {};
  Object.keys(condMapProduitMarche).forEach(function(ean) {
    var m = condMapProduitMarche[ean];
    if (m.marche) marches[m.marche] = true;
  });
  var selM = document.getElementById('map-filter-marche');
  if (!selM) return;
  selM.innerHTML = '<option value="">— Tous les marchés —</option>' +
    Object.keys(marches).sort().map(function(m) {
      return '<option value="' + m + '"' + (m === mapFilterMarche ? ' selected' : '') + '>' + m + '</option>';
    }).join('');
  mapFiltrerSousMarches();
}

function mapFiltrerSousMarches() {
  var sms = {};
  Object.keys(condMapProduitMarche).forEach(function(ean) {
    var m = condMapProduitMarche[ean];
    if (mapFilterMarche && m.marche !== mapFilterMarche) return;
    if (m.sous_marche) sms[m.sous_marche] = true;
  });
  var selS = document.getElementById('map-filter-sm');
  if (!selS) return;
  selS.innerHTML = '<option value="">— Tous les sous-marchés —</option>' +
    Object.keys(sms).sort().map(function(s) {
      return '<option value="' + s + '"' + (s === mapFilterSM ? ' selected' : '') + '>' + s + '</option>';
    }).join('');
}

function mapChangerMarche() {
  var selM = document.getElementById('map-filter-marche');
  mapFilterMarche = selM ? selM.value : '';
  mapFilterSM = '';
  mapFiltrerSousMarches();
  mapEditEan = null;
  mapRender();
}

function mapChangerSM() {
  var selS = document.getElementById('map-filter-sm');
  mapFilterSM = selS ? selS.value : '';
  mapEditEan = null;
  mapRender();
}

function mapRender() {
  var div = document.getElementById('map-content');
  if (!div) return;
  var q = (document.getElementById('map-search') || {}).value || '';
  var res = mapGetFiltered(q);
  var total = Object.keys(condMapProduitMarche).length;

  var cntEl = document.getElementById('map-count');
  if (cntEl) cntEl.textContent = total ? total + ' EANs mappés' : '';

  if (!total) {
    div.innerHTML = '<div class="card" style="text-align:center;padding:24px">' +
      '<p style="font-size:14px;margin-bottom:8px">📂 Aucun mapping chargé</p>' +
      '<p style="color:var(--text-sec);font-size:12px;margin-bottom:16px">Cliquez sur <b>📥 Importer MAP_PRODUIT_MARCHE</b> ci-dessus.</p>' +
      '<p style="color:var(--text-ter);font-size:11px">Un seul import suffit — les données persistent entre les sessions.</p>' +
      '</div>';
    return;
  }

  var rows = res.entries.map(function(ean) {
    var m = condMapProduitMarche[ean];
    var lib = mapLibelle(ean);
    var isEdit = mapEditEan === ean;

    if (isEdit) {
      return '<tr style="background:#fffbea">' +
        '<td style="padding:5px 6px;font-family:monospace;font-size:11px">' + ean + '</td>' +
        '<td style="padding:5px 6px;font-size:11px;color:var(--text-sec)">' + (lib || '—').substring(0,40) + '</td>' +
        '<td style="padding:5px 6px;font-size:11px">' + (m.labo || '') + '</td>' +
        '<td style="padding:5px 6px"><input id="map-edit-mar" value="' + (m.marche || '') + '" style="width:130px;font-size:11px;padding:2px 4px;border:1px solid var(--accent);border-radius:3px"></td>' +
        '<td style="padding:5px 6px"><input id="map-edit-sm" value="' + (m.sous_marche || '') + '" style="width:160px;font-size:11px;padding:2px 4px;border:1px solid var(--accent);border-radius:3px"></td>' +
        '<td style="padding:5px 6px;white-space:nowrap">' +
          '<button onclick="mapSauvegarder(\'' + ean + '\')" style="font-size:10px;padding:2px 8px;background:var(--accent);color:#fff;border:none;border-radius:3px;cursor:pointer;margin-right:4px">✓ OK</button>' +
          '<button onclick="mapAnnulerEdit()" style="font-size:10px;padding:2px 8px;background:#fff;border:1px solid var(--border);border-radius:3px;cursor:pointer">✕</button>' +
        '</td></tr>';
    }

    return '<tr style="border-bottom:1px solid var(--border)">' +
      '<td style="padding:5px 6px;font-family:monospace;font-size:11px;color:var(--text-sec)">' + ean + '</td>' +
      '<td style="padding:5px 6px;font-size:11px" title="' + lib + '">' + (lib || '—').substring(0,38) + (lib.length>38?'…':'') + '</td>' +
      '<td style="padding:5px 6px;font-size:11px">' + (m.labo || '—') + '</td>' +
      '<td style="padding:5px 6px"><span style="font-size:10px;background:#e8f0fe;color:#1a56db;padding:2px 6px;border-radius:3px">' + (m.marche || '—') + '</span></td>' +
      '<td style="padding:5px 6px"><span style="font-size:10px;background:#f0f9f0;color:#166534;padding:2px 6px;border-radius:3px">' + (m.sous_marche || '—') + '</span></td>' +
      '<td style="padding:5px 6px;white-space:nowrap">' +
        '<button onclick="mapEditer(\'' + ean + '\')" style="font-size:10px;padding:2px 7px;background:#fff;border:1px solid var(--border);border-radius:3px;cursor:pointer;margin-right:3px">✏️</button>' +
        '<button onclick="mapSupprimer(\'' + ean + '\')" style="font-size:10px;padding:2px 7px;background:#fff;border:1px solid #dc3545;color:#dc3545;border-radius:3px;cursor:pointer">🗑</button>' +
      '</td></tr>';
  }).join('');

  var activeFilters = [mapFilterMarche, mapFilterSM].filter(Boolean);
  var subtitle = res.filtered + ' produit' + (res.filtered>1?'s':'') +
    (activeFilters.length ? ' dans <b>' + activeFilters.join(' › ') + '</b>' : '') +
    (q ? ' · recherche "<b>' + q + '</b>"' : '') +
    ' · ' + total + ' EANs au total' +
    (!mapFilterMarche && !mapFilterSM && !q && res.entries.length < res.filtered ? ' (60 premiers — utilisez les filtres pour voir tout)' : '');

  div.innerHTML =
    '<div class="card">' +
    // Formulaire ajout
    '<details style="margin-bottom:12px"><summary style="font-size:12px;font-weight:600;cursor:pointer;color:var(--accent)">➕ Ajouter un nouveau mapping EAN</summary>' +
    '<div style="margin-top:10px;display:flex;gap:8px;flex-wrap:wrap;align-items:flex-end">' +
    '<div><label style="font-size:10px;display:block;color:var(--text-sec)">EAN</label><input id="map-new-ean" placeholder="3400930..." style="width:130px;font-size:12px;padding:4px 6px;border:1px solid var(--border);border-radius:var(--radius-sm)"></div>' +
    '<div><label style="font-size:10px;display:block;color:var(--text-sec)">Libellé</label><input id="map-new-lib" placeholder="Nom produit" style="width:200px;font-size:12px;padding:4px 6px;border:1px solid var(--border);border-radius:var(--radius-sm)"></div>' +
    '<div><label style="font-size:10px;display:block;color:var(--text-sec)">Labo</label><input id="map-new-labo" placeholder="COOPER" style="width:130px;font-size:12px;padding:4px 6px;border:1px solid var(--border);border-radius:var(--radius-sm)"></div>' +
    '<div><label style="font-size:10px;display:block;color:var(--text-sec)">Marché</label><input id="map-new-mar" placeholder="PREMIERS_SOINS" style="width:140px;font-size:12px;padding:4px 6px;border:1px solid var(--border);border-radius:var(--radius-sm)"></div>' +
    '<div><label style="font-size:10px;display:block;color:var(--text-sec)">Sous-marché</label><input id="map-new-sm" placeholder="ANTI_DESIN_1" style="width:140px;font-size:12px;padding:4px 6px;border:1px solid var(--border);border-radius:var(--radius-sm)"></div>' +
    '<button onclick="mapAjouter()" style="font-size:12px;padding:5px 14px;background:var(--accent);color:#fff;border:none;border-radius:var(--radius-sm);cursor:pointer">Ajouter</button>' +
    '</div></details>' +
    // Info + compteur
    '<p style="font-size:11px;color:var(--text-sec);margin:0 0 8px 0">' + subtitle + '</p>' +
    // Table
    '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px">' +
    '<thead><tr style="border-bottom:2px solid var(--border);background:var(--bg-alt,#f8f9fa)">' +
    '<th style="text-align:left;padding:6px">EAN</th>' +
    '<th style="text-align:left;padding:6px">Libellé</th>' +
    '<th style="text-align:left;padding:6px">Labo</th>' +
    '<th style="text-align:left;padding:6px">Marché</th>' +
    '<th style="text-align:left;padding:6px">Sous-marché</th>' +
    '<th style="padding:6px"></th>' +
    '</tr></thead><tbody>' + rows + '</tbody></table></div>' +
    '</div>';
}

function mapEditer(ean) {
  mapEditEan = ean;
  mapRender();
  // Focus premier input
  setTimeout(function(){ var i=document.getElementById('map-edit-mar'); if(i)i.focus(); }, 50);
}

function mapAnnulerEdit() {
  mapEditEan = null;
  mapRender();
}

function mapSauvegarder(ean) {
  var mar = (document.getElementById('map-edit-mar') || {}).value || '';
  var sm  = (document.getElementById('map-edit-sm')  || {}).value || '';
  if (condMapProduitMarche[ean]) {
    condMapProduitMarche[ean].marche      = mar.trim().toUpperCase();
    condMapProduitMarche[ean].sous_marche = sm.trim().toUpperCase();
    try { localStorage.setItem('cond_map_produit_marche', JSON.stringify(condMapProduitMarche)); } catch(e){}
    meqCalculerMarchesVirtuels();
  }
  mapEditEan = null;
  mapRender();
}

function mapAjouter() {
  var ean  = ((document.getElementById('map-new-ean')  || {}).value || '').trim().replace(/\.0$/,'');
  var lib  = ((document.getElementById('map-new-lib')  || {}).value || '').trim();
  var labo = ((document.getElementById('map-new-labo') || {}).value || '').trim().toUpperCase();
  var mar  = ((document.getElementById('map-new-mar')  || {}).value || '').trim().toUpperCase();
  var sm   = ((document.getElementById('map-new-sm')   || {}).value || '').trim().toUpperCase();
  if (!ean || !sm) { alert('EAN et Sous-marché sont obligatoires.'); return; }
  condMapProduitMarche[ean] = { labo: labo, marche: mar, sous_marche: sm, libelle: lib };
  try { localStorage.setItem('cond_map_produit_marche', JSON.stringify(condMapProduitMarche)); } catch(e){}
  meqCalculerMarchesVirtuels();
  // Chercher le nouvel EAN
  var inp = document.getElementById('map-search');
  if (inp) { inp.value = ean; }
  mapRender();
}

function mapSupprimer(ean) {
  if (!confirm('Supprimer le mapping EAN ' + ean + ' ?\n' + mapLibelle(ean))) return;
  delete condMapProduitMarche[ean];
  try { localStorage.setItem('cond_map_produit_marche', JSON.stringify(condMapProduitMarche)); } catch(e){}
  meqCalculerMarchesVirtuels();
  mapRender();
}

function mapRechercher() {
  mapEditEan = null;
  mapRender();
}

// ═══════════════════════════════════════════════════════════════════════════
// ONGLET ENGAGEMENTS — Paramétrage PDM cible + engagements par labo × SM
// ═══════════════════════════════════════════════════════════════════════════

// Structure : { [laboNom]: { [smId]: { statut, date_debut, date_fin,
//              pdm_cible, engagement_type, engagement_vol, engagement_pdm } } }
var condEngagements = (function () {
  try { var s = localStorage.getItem('cond_engagements'); return s ? JSON.parse(s) : {}; }
  catch (e) { return {}; }
})();

var engInited = false;
var engLaboSelectionne = '';

function engSauvegarder() {
  try { localStorage.setItem('cond_engagements', JSON.stringify(condEngagements)); } catch(e) {}
}

// Labos depuis toutes les sources disponibles
function engGetLabos() {
  var set = {};
  // Source 1 : condMarchesVirtuels (si ventes importées)
  Object.keys(condMarchesVirtuels).forEach(function(smId) {
    (condMarchesVirtuels[smId].produits || []).forEach(function(p) {
      if (p.labo_nom) set[p.labo_nom] = true;
    });
  });
  // Source 2 : condMapProduitMarche (toujours disponible après import MAP)
  Object.keys(condMapProduitMarche).forEach(function(ean) {
    var m = condMapProduitMarche[ean];
    if (m && m.labo) set[m.labo] = true;
  });
  // Source 3 : engagements déjà saisis
  Object.keys(condEngagements).forEach(function(l) { if (l) set[l] = true; });
  return Object.keys(set).filter(Boolean).sort();
}

function engInit() {
  // Mettre à jour le badge commandes
  var badge = document.getElementById('eng-commandes-badge');
  if (badge && Object.keys(condCommandesEnCours).length) {
    badge.textContent = Object.keys(condCommandesEnCours).length + ' EANs chargés · ' + (condCommandesMeta.date_import || '');
  }
  var sel = document.getElementById('eng-select-labo');
  if (!sel) return;
  var labos = engGetLabos();
  if (!labos.length) {
    sel.innerHTML = '<option value="">— Importez MAP_PRODUIT_MARCHE d\'abord —</option>';
    document.getElementById('eng-content').innerHTML =
      '<div class="card"><p style="color:var(--text-ter);font-size:12px">Importez MAP_PRODUIT_MARCHE via l\'onglet 🗺 MAP Produits pour voir les labos disponibles.</p></div>';
    return;
  }
  sel.innerHTML = '<option value="">— Choisir un labo —</option>' +
    labos.map(function(l) {
      var nbOuverts = engNbMarchesOuverts(l);
      return '<option value="' + l + '"' + (l === engLaboSelectionne ? ' selected' : '') + '>' +
        l + (nbOuverts ? ' ✓ (' + nbOuverts + ' ouverts)' : '') + '</option>';
    }).join('');
  if (engLaboSelectionne) engRenderMC(engLaboSelectionne);
}

function engNbMarchesOuverts(laboNom) {
  if (!condEngagements[laboNom]) return 0;
  return Object.keys(condEngagements[laboNom]).filter(function(sm) {
    return condEngagements[laboNom][sm].statut === 'ouvert';
  }).length;
}

// Calcule la PDM suggérée selon le rang dans le sous-marché
function engPdmSuggerer(laboNom, smId) {
  var sm = condMarchesVirtuels[smId];
  if (!sm || !sm.produits || !sm.produits.length) return 40;
  var totalN = sm.produits.reduce(function(s,p){ return s+(p.qtes_n||0); }, 0);
  if (!totalN) return 40;
  var sorted = sm.produits.slice().sort(function(a,b){ return (b.qtes_n||0)-(a.qtes_n||0); });
  var idx = sorted.findIndex(function(p){ return p.labo_nom === laboNom; });
  var rang = idx >= 0 ? idx + 1 : sorted.length + 1;
  var pdmActuelle = idx >= 0 ? Math.round((sorted[idx].qtes_n||0) / totalN * 100) : 0;
  var suggestion;
  if (totalN < 30)      suggestion = pdmActuelle;                              // petit marché → maintenir
  else if (rang === 1)  suggestion = Math.min(pdmActuelle + 7, 80);            // leader → consolider
  else if (rang === 2)  suggestion = Math.min(pdmActuelle + 12, 75);           // challenger
  else if (rang === 3 && totalN >= 100) suggestion = Math.min(pdmActuelle + 15, 70); // opportunité
  else if (rang >= 4 && totalN >= 150)  suggestion = Math.min(pdmActuelle + 20, 65); // offensive
  else suggestion = pdmActuelle + 5;
  return Math.max(suggestion, 5);
}

// Calcule le plafond disponible sur un sous-marché
// = volume total N-1 tous labos − stock actuel tous labos sur ce SM
function engPlafond(smId) {
  var sm = condMarchesVirtuels[smId];
  if (!sm || !sm.produits) return null;
  var volN1  = sm.produits.reduce(function(s,p){ return s+(p.qtes_n1||0); }, 0);
  // Stock actuel : somme des stocks LGPI pour les EANs de ce SM
  var stock = 0;
  Object.keys(condVentesOspharm).forEach(function(ean) {
    var m = condMapProduitMarche[ean];
    if (m && m.sous_marche === smId) stock += condVentesOspharm[ean].stock || 0;
  });
  return { volN1: volN1, stock: stock, plafond: Math.max(0, volN1 - stock) };
}

function engRender() {
  var div = document.getElementById('eng-content');
  if (!div) return;
  var sel = document.getElementById('eng-select-labo');
  var laboNom = sel ? sel.value : '';
  engLaboSelectionne = laboNom;

  if (!laboNom) {
    div.innerHTML = '<div class="card"><p style="color:var(--text-ter);font-size:12px">Sélectionnez un labo pour paramétrer ses engagements.</p></div>';
    return;
  }

  if (!condEngagements[laboNom]) condEngagements[laboNom] = {};

  // Trouver tous les sous-marchés où ce labo est présent
  // Source 1 : condMarchesVirtuels (ventes importées)
  var smsSet = {};
  Object.keys(condMarchesVirtuels).forEach(function(smId) {
    var sm = condMarchesVirtuels[smId];
    if (sm.produits && sm.produits.some(function(p){ return p.labo_nom === laboNom; })) {
      smsSet[smId] = true;
    }
  });
  // Source 2 : condMapProduitMarche (toujours disponible)
  Object.keys(condMapProduitMarche).forEach(function(ean) {
    var m = condMapProduitMarche[ean];
    if (m && m.labo === laboNom && m.sous_marche) smsSet[m.sous_marche] = true;
  });
  // Source 3 : engagements déjà saisis pour ce labo
  if (condEngagements[laboNom]) {
    Object.keys(condEngagements[laboNom]).forEach(function(smId){ smsSet[smId] = true; });
  }
  var sms = Object.keys(smsSet);

  var hasVentes = Object.keys(condMarchesVirtuels).length > 0;

  if (!sms.length) {
    div.innerHTML = '<div class="card"><p style="color:var(--text-ter);font-size:12px">Aucun sous-marché trouvé pour ' + laboNom + '. Vérifiez que MAP_PRODUIT_MARCHE est importé.</p></div>';
    return;
  }

  // Trier : ouverts en premier, puis par volume décroissant
  sms.sort(function(a, b) {
    var ea = condEngagements[laboNom][a] || {};
    var eb = condEngagements[laboNom][b] || {};
    var statA = ea.statut || 'non_ouvert';
    var statB = eb.statut || 'non_ouvert';
    if (statA === 'ouvert' && statB !== 'ouvert') return -1;
    if (statB === 'ouvert' && statA !== 'ouvert') return 1;
    var smA = condMarchesVirtuels[a]; var smB = condMarchesVirtuels[b];
    var vA = smA ? smA.produits.reduce(function(s,p){ return s+(p.qtes_n||0); },0) : 0;
    var vB = smB ? smB.produits.reduce(function(s,p){ return s+(p.qtes_n||0); },0) : 0;
    return vB - vA;
  });

  var rows = sms.map(function(smId) {
    var e   = condEngagements[laboNom][smId] || {};
    var sm  = condMarchesVirtuels[smId];
    // Libellé depuis MAP si SM pas encore dans condMarchesVirtuels
    var smLibFallback = sm ? (sm.libelle || smId) : smId;
    var smMarcheFallback = sm ? (sm.marche || '') : '';
    // Chercher marche/libelle dans condMapProduitMarche si manquant
    if (!smMarcheFallback) {
      var eanEx = Object.keys(condMapProduitMarche).find(function(e){
        var m = condMapProduitMarche[e]; return m && m.labo === laboNom && m.sous_marche === smId;
      });
      if (eanEx) smMarcheFallback = condMapProduitMarche[eanEx].marche || '';
    }
    var prd = sm ? sm.produits.find(function(p){ return p.labo_nom === laboNom; }) : null;
    var qnLabo  = prd ? (prd.qtes_n  || 0) : 0;
    var qn1Labo = prd ? (prd.qtes_n1 || 0) : 0;
    var plaf = engPlafond(smId);
    var totalN  = sm ? sm.produits.reduce(function(s,p){ return s+(p.qtes_n||0); },0) : 0;
    var pdmAct  = totalN > 0 ? Math.round(qnLabo / totalN * 100) : 0;
    var pdmSug  = engPdmSuggerer(laboNom, smId);
    var statut  = e.statut || 'non_ouvert';
    var smLib   = smLibFallback;

    var statutBadge = statut === 'ouvert'
      ? '<span style="font-size:10px;background:#d4edda;color:#155724;padding:2px 7px;border-radius:3px">✓ Ouvert</span>'
      : statut === 'ferme'
        ? '<span style="font-size:10px;background:#f8d7da;color:#721c24;padding:2px 7px;border-radius:3px">✕ Fermé</span>'
        : '<span style="font-size:10px;background:#e2e3e5;color:#495057;padding:2px 7px;border-radius:3px">— Non ouvert</span>';

    var pdmCible   = e.pdm_cible    !== undefined ? e.pdm_cible    : pdmSug;
    var engVol     = e.engagement_vol !== undefined ? e.engagement_vol : '';
    var engPdm     = e.engagement_pdm !== undefined ? e.engagement_pdm : '';
    var engType    = e.engagement_type || 'volume';
    var dd         = e.date_debut || '';
    var df         = e.date_fin   || '';

    var plafHtml = plaf
      ? '<span style="font-size:10px">N-1: <b>' + plaf.volN1 + 'u.</b> − Stock: <b>' + plaf.stock + '</b> = <b style="color:' + (plaf.plafond < 50 ? '#dc3545' : '#155724') + '">' + plaf.plafond + 'u.</b> dispo</span>'
      : '—';

    var eid = smId.replace(/[^a-zA-Z0-9]/g,'_');

    return '<tr style="border-bottom:1px solid var(--border);vertical-align:top">' +
      // Sous-marché
      '<td style="padding:8px 6px">' +
        '<div style="font-weight:600;font-size:12px">' + smLib + '</div>' +
        '<div style="font-size:10px;color:var(--text-ter)">' + smId + (smMarcheFallback ? ' · ' + smMarcheFallback : '') + '</div>' +
        '<div style="margin-top:3px">' + statutBadge + '</div>' +
      '</td>' +
      // Volumes
      '<td style="padding:8px 6px;font-size:11px;text-align:right">' +
        (sm
          ? '<div><b>' + qnLabo + '</b> u. N</div><div style="color:var(--text-sec)">' + qn1Labo + ' u. N-1</div><div style="color:var(--text-sec)">Marché: ' + totalN + 'u.</div>'
          : '<div style="color:var(--text-ter);font-size:10px">Importez<br>ventes LGPI</div>') +
      '</td>' +
      // PDM
      '<td style="padding:8px 6px;text-align:center">' +
        '<div style="font-size:13px;font-weight:700;color:' + (pdmAct >= pdmCible ? '#155724' : '#856404') + '">' + pdmAct + '%</div>' +
        '<div style="font-size:10px;color:var(--text-sec)">actuelle</div>' +
      '</td>' +
      // Plafond
      '<td style="padding:8px 6px">' + plafHtml + '</td>' +
      // Paramétrage
      '<td style="padding:8px 6px;min-width:320px">' +
        '<div style="display:flex;gap:6px;flex-wrap:wrap;align-items:center;margin-bottom:6px">' +
          '<select onchange="engSetStatut(\'' + laboNom.replace(/'/g,"\\'") + '\',\'' + smId + '\',this.value)" style="font-size:11px;padding:3px 6px;border:1px solid var(--border);border-radius:3px">' +
            '<option value="non_ouvert"' + (statut==='non_ouvert'?' selected':'') + '>Non ouvert</option>' +
            '<option value="ouvert"'     + (statut==='ouvert'    ?' selected':'') + '>Ouvert</option>' +
            '<option value="ferme"'      + (statut==='ferme'     ?' selected':'') + '>Fermé</option>' +
          '</select>' +
          (statut === 'ouvert' ?
            '<input type="date" value="' + dd + '" onchange="engSet(\'' + laboNom.replace(/'/g,"\\'") + '\',\'' + smId + '\',\'date_debut\',this.value)" style="font-size:11px;padding:3px 5px;border:1px solid var(--border);border-radius:3px" title="Date début">' +
            '<span style="font-size:10px;color:var(--text-ter)">→</span>' +
            '<input type="date" value="' + df + '" onchange="engSet(\'' + laboNom.replace(/'/g,"\\'") + '\',\'' + smId + '\',\'date_fin\',this.value)" style="font-size:11px;padding:3px 5px;border:1px solid var(--border);border-radius:3px" title="Date fin">'
          : '') +
        '</div>' +
        (statut === 'ouvert' ?
          '<div style="display:flex;gap:6px;flex-wrap:wrap;align-items:center">' +
            '<label style="font-size:10px;color:var(--text-sec)">PDM cible %</label>' +
            '<input type="number" min="0" max="100" value="' + pdmCible + '" ' +
              'onchange="engSet(\'' + laboNom.replace(/'/g,"\\'") + '\',\'' + smId + '\',\'pdm_cible\',+this.value)" ' +
              'style="width:52px;font-size:11px;padding:3px 5px;border:1px solid var(--accent);border-radius:3px">' +
            '<span style="font-size:10px;color:var(--accent)">← suggéré: ' + pdmSug + '%</span>' +
          '</div>' +
          '<div style="display:flex;gap:6px;flex-wrap:wrap;align-items:center;margin-top:4px">' +
            '<select onchange="engSet(\'' + laboNom.replace(/'/g,"\\'") + '\',\'' + smId + '\',\'engagement_type\',this.value)" style="font-size:11px;padding:3px 5px;border:1px solid var(--border);border-radius:3px">' +
              '<option value="volume"'  + (engType==='volume'  ?' selected':'') + '>Vol. annuel</option>' +
              '<option value="pdm"'     + (engType==='pdm'     ?' selected':'') + '>PDM min</option>' +
              '<option value="les_deux"'+ (engType==='les_deux'?' selected':'') + '>Les deux</option>' +
            '</select>' +
            (engType !== 'pdm' ?
              '<input type="number" min="0" value="' + (engVol||'') + '" placeholder="vol. u." ' +
                'onchange="engSet(\'' + laboNom.replace(/'/g,"\\'") + '\',\'' + smId + '\',\'engagement_vol\',+this.value)" ' +
                'style="width:70px;font-size:11px;padding:3px 5px;border:1px solid var(--border);border-radius:3px">'
            : '') +
            (engType !== 'volume' ?
              '<input type="number" min="0" max="100" value="' + (engPdm||'') + '" placeholder="PDM min %" ' +
                'onchange="engSet(\'' + laboNom.replace(/'/g,"\\'") + '\',\'' + smId + '\',\'engagement_pdm\',+this.value)" ' +
                'style="width:70px;font-size:11px;padding:3px 5px;border:1px solid var(--border);border-radius:3px">'
            : '') +
          '</div>'
        : '<div style="font-size:10px;color:var(--text-ter);margin-top:4px">Ouvrez le marché pour paramétrer.</div>') +
      '</td>' +
    '</tr>';
  }).join('');

  var nbOuverts  = sms.filter(function(s){ var e=condEngagements[laboNom][s]||{}; return e.statut==='ouvert'; }).length;
  var nbNonOuverts = sms.length - nbOuverts;

  div.innerHTML =
    '<div class="card">' +
    '<p class="card-title">' + laboNom + ' — Engagements marchés</p>' +
    '<p style="font-size:11px;color:var(--text-sec);margin:0 0 10px 0">' +
      sms.length + ' sous-marchés · <b style="color:#155724">' + nbOuverts + ' ouverts</b>' +
      (nbNonOuverts ? ' · <span style="color:var(--text-ter)">' + nbNonOuverts + ' non ouverts</span>' : '') +
      ' · Modifications sauvegardées automatiquement' +
    '</p>' +
    '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px">' +
    '<thead><tr style="border-bottom:2px solid var(--border);background:var(--bg-alt,#f8f9fa)">' +
    '<th style="text-align:left;padding:8px 6px">Sous-marché</th>' +
    '<th style="text-align:right;padding:8px 6px">Volumes</th>' +
    '<th style="text-align:center;padding:8px 6px">PDM act.</th>' +
    '<th style="text-align:left;padding:8px 6px">Plafond dispo</th>' +
    '<th style="text-align:left;padding:8px 6px">Paramétrage</th>' +
    '</tr></thead><tbody>' + rows + '</tbody></table></div>' +
    '</div>';
}

function engSetStatut(laboNom, smId, val) {
  if (!condEngagements[laboNom]) condEngagements[laboNom] = {};
  if (!condEngagements[laboNom][smId]) condEngagements[laboNom][smId] = {};
  condEngagements[laboNom][smId].statut = val;
  engSauvegarder();
  engRender();
}

function engSet(laboNom, smId, champ, val) {
  if (!condEngagements[laboNom]) condEngagements[laboNom] = {};
  if (!condEngagements[laboNom][smId]) condEngagements[laboNom][smId] = {};
  condEngagements[laboNom][smId][champ] = val;
  engSauvegarder();
  if (champ === 'engagement_type') engRender(); // re-render pour afficher/masquer les inputs
}

// ═══════════════════════════════════════════════════════════════════════════
// MARCHÉS COMMERCIAUX LABO — groupements de sous-marchés MAP
// Structure : condMarchesCommerciaux[laboNom] = [
//   { id, nom, sms: [smId,...], engagement_type, engagement_vol, engagement_pdm,
//     date_debut, date_fin }
// ]
// ═══════════════════════════════════════════════════════════════════════════

var condMarchesCommerciaux = (function () {
  try { var s = localStorage.getItem('cond_marches_commerciaux'); return s ? JSON.parse(s) : {}; }
  catch (e) { return {}; }
})();

function mcSauvegarder() {
  try { localStorage.setItem('cond_marches_commerciaux', JSON.stringify(condMarchesCommerciaux)); } catch(e) {}
}

function mcIdGenerer() {
  return 'mc_' + Date.now() + '_' + Math.random().toString(36).substr(2,5);
}

// Tous les sous-marchés d'un labo (depuis MAP ou condMarchesVirtuels)
function mcGetSousMarches(laboNom) {
  var set = {};
  Object.keys(condMarchesVirtuels).forEach(function(smId) {
    var sm = condMarchesVirtuels[smId];
    if (sm.produits && sm.produits.some(function(p){ return p.labo_nom === laboNom; })) set[smId] = true;
  });
  Object.keys(condMapProduitMarche).forEach(function(ean) {
    var m = condMapProduitMarche[ean];
    if (m && m.labo === laboNom && m.sous_marche) set[m.sous_marche] = true;
  });
  return Object.keys(set).sort();
}

// Sous-marchés déjà affectés à un marché commercial pour ce labo
function mcGetSmsAffectes(laboNom) {
  var affectes = {};
  (condMarchesCommerciaux[laboNom] || []).forEach(function(mc) {
    (mc.sms || []).forEach(function(sm) { affectes[sm] = mc.nom; });
  });
  return affectes;
}

// Agrégats volumes pour un marché commercial
function mcAgregatVolumes(laboNom, smsIds) {
  var qn = 0, qn1 = 0, can = 0, stock = 0;
  var volMarcheN = 0, volMarcheN1 = 0;
  smsIds.forEach(function(smId) {
    var sm = condMarchesVirtuels[smId];
    if (sm && sm.produits) {
      var prd = sm.produits.find(function(p){ return p.labo_nom === laboNom; });
      if (prd) { qn += prd.qtes_n||0; qn1 += prd.qtes_n1||0; }
      sm.produits.forEach(function(p){ volMarcheN += p.qtes_n||0; volMarcheN1 += p.qtes_n1||0; });
    }
    // Stock depuis condVentesOspharm
    Object.keys(condVentesOspharm).forEach(function(ean) {
      var m = condMapProduitMarche[ean];
      if (m && m.sous_marche === smId) {
        if (m.labo === laboNom) can += condVentesOspharm[ean].ca_n || 0;
        stock += condVentesOspharm[ean].stock || 0;
      }
    });
  });
  var pdmAct = volMarcheN > 0 ? Math.round(qn / volMarcheN * 100) : 0;
  // Plafond = volume N-1 tous labos - stock actuel
  var plafond = Math.max(0, volMarcheN1 - stock);
  return { qn: qn, qn1: qn1, can: Math.round(can), stock: stock,
           volMarcheN: volMarcheN, volMarcheN1: volMarcheN1,
           pdmAct: pdmAct, plafond: plafond };
}

// ── Rendu principal onglet Engagements (remplace engRender) ─────────────────
function engRenderMC(laboNom) {
  var div = document.getElementById('eng-content');
  if (!div) return;
  if (!laboNom) {
    div.innerHTML = '<div class="card"><p style="color:var(--text-ter);font-size:12px">Sélectionnez un labo.</p></div>';
    return;
  }

  if (!condMarchesCommerciaux[laboNom]) condMarchesCommerciaux[laboNom] = [];
  var mcs = condMarchesCommerciaux[laboNom];
  var allSms = mcGetSousMarches(laboNom);
  var affectes = mcGetSmsAffectes(laboNom);
  var nonAffectes = allSms.filter(function(sm){ return !affectes[sm]; });
  var hasVentes = Object.keys(condMarchesVirtuels).length > 0;

  // ── Tableau des marchés commerciaux ────────────────────────────────────
  var mcRows = mcs.map(function(mc, idx) {
    var agg = hasVentes ? mcAgregatVolumes(laboNom, mc.sms || []) : null;
    var engVol = mc.engagement_vol || 0;
    var engPdm = mc.engagement_pdm || 0;
    var engType = mc.engagement_type || 'volume';

    // Commandes en cours pour ce marché commercial
    var qteEnCours = cmdEnCoursVolume(laboNom, mc.sms || []);
    var hasCmds = Object.keys(condCommandesEnCours).length > 0;

    // Statut avancement : ventes + commandes en cours
    var statutHtml = '';
    if (agg && engVol > 0) {
      var totalAvec = agg.qn + qteEnCours;
      var pctVentes = Math.round(agg.qn / engVol * 100);
      var pctTotal  = Math.round(totalAvec / engVol * 100);
      var color = pctTotal >= 100 ? '#155724' : pctTotal >= 60 ? '#856404' : '#721c24';
      var barVentes = Math.min(Math.round(agg.qn / engVol * 100), 100);
      var barCmds   = Math.min(Math.round(qteEnCours / engVol * 100), 100 - barVentes);
      statutHtml =
        '<div style="margin-top:4px">' +
        '<div style="background:#e9ecef;border-radius:4px;height:8px;width:140px;display:inline-block;vertical-align:middle;position:relative;overflow:hidden">' +
        '<div style="background:' + color + ';width:' + barVentes + '%;height:100%;position:absolute;left:0"></div>' +
        (qteEnCours > 0 ? '<div style="background:#5B9BD5;width:' + barCmds + '%;height:100%;position:absolute;left:' + barVentes + '%;opacity:0.7"></div>' : '') +
        '</div>' +
        ' <span style="font-size:10px;color:' + color + ';font-weight:700">' + pctTotal + '%</span>' +
        '<span style="font-size:10px;color:var(--text-sec)"> · <b>' + agg.qn + '</b> vendus' +
        (qteEnCours > 0 ? ' + <span style="color:#1a56db"><b>' + qteEnCours + '</b> en commande</span>' : '') +
        ' / ' + engVol + ' u. engagement</span>' +
        '</div>' +
        (totalAvec > agg.plafond && agg.plafond > 0 ? '<div style="font-size:10px;color:#721c24;margin-top:2px">⚠ Dépasse le plafond disponible (' + agg.plafond + ' u.)</div>' : '');
    } else if (agg && hasCmds && qteEnCours > 0) {
      statutHtml = '<div style="font-size:10px;color:#1a56db;margin-top:4px">📦 ' + qteEnCours + ' u. en commande (pas d\'engagement défini)</div>';
    }

    // Plafond
    var plafHtml = agg
      ? '<span style="font-size:10px">Plafond: <b style="color:' + (agg.plafond < 50?'#dc3545':'#155724') + '">' + agg.plafond + 'u.</b> dispo (N-1:' + agg.volMarcheN1 + ' − stk:' + agg.stock + ')</span>'
      : '<span style="font-size:10px;color:var(--text-ter)">Importez ventes LGPI</span>';

    // Alerte dépassement plafond
    var alertePlafond = (agg && engVol > 0 && agg.plafond < (engVol - agg.qn))
      ? '<span style="font-size:10px;background:#f8d7da;color:#721c24;padding:2px 6px;border-radius:3px;margin-left:6px">⚠ Plafond insuffisant</span>'
      : '';

    var smBadges = (mc.sms || []).map(function(s){
      var lib = condMarchesVirtuels[s] ? (condMarchesVirtuels[s].libelle || s) : s;
      return '<span style="font-size:9px;background:#e8f0fe;color:#1a56db;padding:1px 5px;border-radius:3px;margin:1px">' + lib + '</span>';
    }).join('');

    return '<tr style="border-bottom:1px solid var(--border);vertical-align:top">' +
      '<td style="padding:8px">' +
        '<div style="font-weight:700;font-size:13px">' + mc.nom + alertePlafond + '</div>' +
        '<div style="margin-top:4px;line-height:1.8">' + smBadges + '</div>' +
        '<div style="margin-top:4px;font-size:10px;color:var(--text-sec)">' +
          (mc.date_debut ? mc.date_debut + ' → ' + (mc.date_fin||'?') : 'Pas de période définie') +
        '</div>' +
      '</td>' +
      '<td style="padding:8px;text-align:right;font-size:11px">' +
        (agg ? '<div><b style="font-size:13px">' + agg.qn + '</b> u. N</div>' +
               '<div style="color:var(--text-sec)">' + agg.qn1 + ' u. N-1</div>' +
               '<div style="color:var(--text-sec)">PDM: <b>' + agg.pdmAct + '%</b></div>'
             : '<div style="color:var(--text-ter);font-size:10px">—</div>') +
      '</td>' +
      '<td style="padding:8px">' + plafHtml + statutHtml + '</td>' +
      '<td style="padding:8px;font-size:11px;min-width:200px">' +
        '<div style="display:flex;gap:4px;flex-wrap:wrap;align-items:center;margin-bottom:4px">' +
          '<select onchange="mcSetChamp(\'' + laboNom.replace(/'/g,"\\'") + '\',' + idx + ',\'engagement_type\',this.value)" style="font-size:10px;padding:2px 4px;border:1px solid var(--border);border-radius:3px">' +
            '<option value="volume"'  + (engType==='volume'  ?' selected':'') + '>Vol. annuel</option>' +
            '<option value="pdm"'     + (engType==='pdm'     ?' selected':'') + '>PDM min</option>' +
            '<option value="les_deux"'+ (engType==='les_deux'?' selected':'') + '>Les deux</option>' +
          '</select>' +
          (engType !== 'pdm' ? '<input type="number" value="' + (engVol||'') + '" placeholder="u./an" onchange="mcSetChamp(\'' + laboNom.replace(/'/g,"\\'") + '\',' + idx + ',\'engagement_vol\',+this.value)" style="width:65px;font-size:11px;padding:2px 4px;border:1px solid var(--border);border-radius:3px">' : '') +
          (engType !== 'volume' ? '<input type="number" value="' + (engPdm||'') + '" placeholder="PDM%" onchange="mcSetChamp(\'' + laboNom.replace(/'/g,"\\'") + '\',' + idx + ',\'engagement_pdm\',+this.value)" style="width:55px;font-size:11px;padding:2px 4px;border:1px solid var(--border);border-radius:3px">' : '') +
        '</div>' +
        '<div style="display:flex;gap:4px;align-items:center">' +
          '<input type="date" value="' + (mc.date_debut||'') + '" onchange="mcSetChamp(\'' + laboNom.replace(/'/g,"\\'") + '\',' + idx + ',\'date_debut\',this.value)" style="font-size:10px;padding:2px 4px;border:1px solid var(--border);border-radius:3px">' +
          '<span style="font-size:10px;color:var(--text-ter)">→</span>' +
          '<input type="date" value="' + (mc.date_fin||'') + '" onchange="mcSetChamp(\'' + laboNom.replace(/'/g,"\\'") + '\',' + idx + ',\'date_fin\',this.value)" style="font-size:10px;padding:2px 4px;border:1px solid var(--border);border-radius:3px">' +
        '</div>' +
      '</td>' +
      '<td style="padding:8px;text-align:center">' +
        '<button onclick="mcEditerSms(\'' + laboNom.replace(/'/g,"\\'") + '\',' + idx + ')" style="font-size:10px;padding:3px 8px;border:1px solid var(--border);background:#fff;border-radius:3px;cursor:pointer;display:block;margin-bottom:4px;width:100%">✏️ Sous-marchés</button>' +
        '<button onclick="mcSupprimer(\'' + laboNom.replace(/'/g,"\\'") + '\',' + idx + ')" style="font-size:10px;padding:3px 8px;border:1px solid #dc3545;color:#dc3545;background:#fff;border-radius:3px;cursor:pointer;width:100%">🗑 Supprimer</button>' +
      '</td>' +
    '</tr>';
  }).join('');

  // ── Non affectés ────────────────────────────────────────────────────────
  var nonAffectesHtml = '';
  if (nonAffectes.length) {
    nonAffectesHtml = '<div class="card" style="margin-top:8px;border:1px dashed var(--border)">' +
      '<p style="font-size:11px;color:var(--text-sec);margin:0 0 6px 0"><b>' + nonAffectes.length + ' sous-marché' + (nonAffectes.length>1?'s':'') + ' non affecté' + (nonAffectes.length>1?'s':'') + ' à un marché commercial :</b></p>' +
      '<div style="line-height:2">' +
      nonAffectes.map(function(sm) {
        var lib = condMarchesVirtuels[sm] ? (condMarchesVirtuels[sm].libelle || sm) : sm;
        var qn = 0;
        if (condMarchesVirtuels[sm]) {
          var prd = condMarchesVirtuels[sm].produits.find(function(p){ return p.labo_nom === laboNom; });
          if (prd) qn = prd.qtes_n || 0;
        }
        return '<span style="font-size:10px;background:#fff3cd;color:#856404;padding:2px 7px;border-radius:3px;margin:2px;display:inline-block">' + lib + (qn ? ' · ' + qn + 'u.' : '') + '</span>';
      }).join('') +
      '</div>' +
      '<p style="font-size:10px;color:var(--text-ter);margin-top:6px">Créez un marché commercial et ajoutez-y ces sous-marchés.</p>' +
      '</div>';
  }

  // ── Formulaire ajout marché commercial ─────────────────────────────────
  div.innerHTML =
    '<div class="card">' +
    '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px">' +
    '<p class="card-title" style="margin:0">' + laboNom + ' — Marchés commerciaux</p>' +
    '<button onclick="mcAjouter(\'' + laboNom.replace(/'/g,"\\'") + '\')" style="font-size:11px;padding:5px 14px;background:var(--accent);color:#fff;border:none;border-radius:var(--radius-sm);cursor:pointer">+ Nouveau marché</button>' +
    '</div>' +
    (mcs.length
      ? '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px">' +
        '<thead><tr style="border-bottom:2px solid var(--border);background:var(--bg-alt,#f8f9fa)">' +
        '<th style="text-align:left;padding:8px">Marché commercial</th>' +
        '<th style="text-align:right;padding:8px">Volumes</th>' +
        '<th style="text-align:left;padding:8px">Plafond / Avancement</th>' +
        '<th style="text-align:left;padding:8px">Engagement</th>' +
        '<th style="padding:8px"></th>' +
        '</tr></thead><tbody>' + mcRows + '</tbody></table></div>'
      : '<p style="color:var(--text-ter);font-size:12px">Aucun marché commercial défini. Cliquez sur "+ Nouveau marché".</p>') +
    '</div>' + nonAffectesHtml;
}

function mcAjouter(laboNom) {
  var nom = prompt('Nom du marché commercial (ex: OTC, Premiers Soins) :');
  if (!nom || !nom.trim()) return;
  if (!condMarchesCommerciaux[laboNom]) condMarchesCommerciaux[laboNom] = [];
  condMarchesCommerciaux[laboNom].push({
    id: mcIdGenerer(), nom: nom.trim(),
    sms: [], engagement_type: 'volume', engagement_vol: 0, engagement_pdm: 0,
    date_debut: '', date_fin: ''
  });
  mcSauvegarder();
  engRenderMC(laboNom);
  // Ouvrir immédiatement l'éditeur de sous-marchés
  var idx = condMarchesCommerciaux[laboNom].length - 1;
  setTimeout(function(){ mcEditerSms(laboNom, idx); }, 100);
}

function mcSupprimer(laboNom, idx) {
  var mc = (condMarchesCommerciaux[laboNom] || [])[idx];
  if (!mc || !confirm('Supprimer le marché "' + mc.nom + '" ?')) return;
  condMarchesCommerciaux[laboNom].splice(idx, 1);
  mcSauvegarder();
  engRenderMC(laboNom);
}

function mcSetChamp(laboNom, idx, champ, val) {
  var mc = (condMarchesCommerciaux[laboNom] || [])[idx];
  if (!mc) return;
  mc[champ] = val;
  mcSauvegarder();
  if (champ === 'engagement_type') engRenderMC(laboNom); // re-render pour inputs
}

// Éditeur de sous-marchés : popup inline
function mcEditerSms(laboNom, idx) {
  var mc = (condMarchesCommerciaux[laboNom] || [])[idx];
  if (!mc) return;
  var allSms = mcGetSousMarches(laboNom);
  var affectes = mcGetSmsAffectes(laboNom);
  var hasVentes = Object.keys(condMarchesVirtuels).length > 0;

  var checkboxes = allSms.map(function(smId) {
    var lib = condMarchesVirtuels[smId] ? (condMarchesVirtuels[smId].libelle || smId) : smId;
    var checked = (mc.sms || []).indexOf(smId) >= 0;
    var autreMarche = affectes[smId] && affectes[smId] !== mc.nom;
    var qn = 0;
    if (hasVentes && condMarchesVirtuels[smId]) {
      var prd = condMarchesVirtuels[smId].produits.find(function(p){ return p.labo_nom === laboNom; });
      if (prd) qn = prd.qtes_n || 0;
    }
    return '<label style="display:flex;align-items:center;gap:6px;padding:4px 0;' + (autreMarche?'opacity:0.4':'') + '">' +
      '<input type="checkbox" ' + (checked?'checked':'') + (autreMarche?'disabled':'') +
      ' onchange="mcToggleSm(\'' + laboNom.replace(/'/g,"\\'") + '\',' + idx + ',\'' + smId + '\',this.checked)">' +
      '<span style="font-size:11px"><b>' + smId + '</b> — ' + lib + (qn ? ' <span style="color:var(--text-sec)">(' + qn + ' u.)</span>' : '') + (autreMarche ? ' <span style="font-size:10px;color:var(--text-ter)">[→ ' + affectes[smId] + ']</span>' : '') + '</span>' +
      '</label>';
  }).join('');

  var overlay = document.createElement('div');
  overlay.id = 'mc-overlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.4);z-index:1000;display:flex;align-items:center;justify-content:center';
  overlay.innerHTML =
    '<div style="background:#fff;border-radius:8px;padding:24px;max-width:560px;width:90%;max-height:80vh;overflow-y:auto;box-shadow:0 8px 32px rgba(0,0,0,0.2)">' +
    '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px">' +
    '<h3 style="margin:0;font-size:14px">' + laboNom + ' · ' + mc.nom + ' — Sous-marchés</h3>' +
    '<button onclick="document.getElementById(\'mc-overlay\').remove();engRenderMC(\'' + laboNom.replace(/'/g,"\\'") + '\')" style="border:none;background:none;font-size:18px;cursor:pointer;color:var(--text-sec)">✕</button>' +
    '</div>' +
    '<p style="font-size:11px;color:var(--text-sec);margin:0 0 12px 0">Cochez les sous-marchés MAP qui composent le marché "' + mc.nom + '". Les sous-marchés grisés sont déjà affectés à un autre marché commercial.</p>' +
    checkboxes +
    '<div style="margin-top:16px;text-align:right">' +
    '<button onclick="document.getElementById(\'mc-overlay\').remove();engRenderMC(\'' + laboNom.replace(/'/g,"\\'") + '\')" style="padding:6px 18px;background:var(--accent);color:#fff;border:none;border-radius:var(--radius-sm);cursor:pointer;font-size:12px">Fermer</button>' +
    '</div></div>';
  document.body.appendChild(overlay);
}

function mcToggleSm(laboNom, idx, smId, checked) {
  var mc = (condMarchesCommerciaux[laboNom] || [])[idx];
  if (!mc) return;
  if (!mc.sms) mc.sms = [];
  if (checked) {
    if (mc.sms.indexOf(smId) < 0) mc.sms.push(smId);
  } else {
    mc.sms = mc.sms.filter(function(s){ return s !== smId; });
  }
  mcSauvegarder();
}

// ═══════════════════════════════════════════════════════════════════════════
// COMMANDES EN COURS — import XLSX extrait du PDF LGPI
// Structure : condCommandesEnCours = {
//   [ean]: { qte: N, fournisseur: '...', date_cde: '...', no_cde: '...' }
// }
// Sémantique : commandes passées mais pas encore reçues (snapshot LGPI)
// ═══════════════════════════════════════════════════════════════════════════

var condCommandesEnCours = (function () {
  try { var s = localStorage.getItem('cond_commandes_en_cours'); return s ? JSON.parse(s) : {}; }
  catch (e) { return {}; }
})();

var condCommandesMeta = (function () {
  try { var s = localStorage.getItem('cond_commandes_meta'); return s ? JSON.parse(s) : {}; }
  catch (e) { return {}; }
})();

function cmdEnCoursSauvegarder() {
  try {
    localStorage.setItem('cond_commandes_en_cours', JSON.stringify(condCommandesEnCours));
    localStorage.setItem('cond_commandes_meta',     JSON.stringify(condCommandesMeta));
  } catch(e) {}
}

// Import XLSX commandes (généré par extraire_commandes_lgpi.py)
// Colonnes attendues : NO_CDE | FOURNISSEUR | DATE_CDE | DATE_LIVRAISON | EAN | DESIGNATION | QTE_CDEE | PA_NET | TOTAL_HT
function engImporterCommandesXLSX() {
  var input = document.createElement('input');
  input.type = 'file'; input.accept = '.xlsx,.xls';
  input.onchange = function (e) {
    var file = e.target.files[0]; if (!file) return;
    var reader = new FileReader();
    reader.onload = function (ev) {
      try {
        var wb = XLSX.read(ev.target.result, { type: 'array' });
        var ws = wb.Sheets[wb.SheetNames[0]];
        var rows = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' });
        if (rows.length < 2) { alert('Fichier vide.'); return; }

        var hdrs = rows[0].map(function(h){ return String(h).toUpperCase().trim(); });
        function col(n) { var i = hdrs.indexOf(n); return i >= 0 ? i : -1; }
        var iEAN  = col('EAN');
        var iQTE  = col('QTE_CDEE');
        var iFRN  = col('FOURNISSEUR');
        var iDATE = col('DATE_CDE');
        var iNO   = col('NO_CDE');
        var iPA   = col('PA_NET');

        if (iEAN < 0 || iQTE < 0) {
          alert('Colonnes EAN et QTE_CDEE introuvables.\nVérifiez que le fichier a été généré par extraire_commandes_lgpi.py');
          return;
        }

        // Remplacer complètement (snapshot)
        condCommandesEnCours = {};
        var nb = 0; var fournisseurs = {};

        rows.slice(1).forEach(function (r) {
          var ean  = String(r[iEAN]  || '').trim().replace(/\.0$/, '');
          var qte  = parseFloat(String(r[iQTE]  || '0').replace(',','.')) || 0;
          if (!ean || !qte) return;
          var frn  = iFRN  >= 0 ? String(r[iFRN]  || '').trim() : '';
          var date = iDATE >= 0 ? String(r[iDATE] || '').trim() : '';
          var no   = iNO   >= 0 ? String(r[iNO]   || '').trim() : '';
          var pa   = iPA   >= 0 ? (parseFloat(String(r[iPA] || '0').replace(',','.')) || 0) : 0;

          if (!condCommandesEnCours[ean]) {
            condCommandesEnCours[ean] = { qte: 0, fournisseur: frn, date_cde: date, no_cde: no, pa_net: pa };
          }
          condCommandesEnCours[ean].qte += qte; // cumuler si même EAN dans plusieurs commandes
          fournisseurs[frn] = true;
          nb++;
        });

        condCommandesMeta = {
          fichier:      file.name,
          date_import:  new Date().toISOString().slice(0, 10),
          nb_lignes:    nb,
          nb_eans:      Object.keys(condCommandesEnCours).length,
          fournisseurs: Object.keys(fournisseurs).sort()
        };

        cmdEnCoursSauvegarder();
        if (engLaboSelectionne) engRenderMC(engLaboSelectionne);
        // Mettre à jour le badge
        var badge = document.getElementById('eng-commandes-badge');
        if (badge) badge.textContent = Object.keys(condCommandesEnCours).length + ' EANs chargés · ' + condCommandesMeta.date_import;

        alert('✅ Commandes en cours importées\n' +
              '• ' + nb + ' lignes · ' + Object.keys(condCommandesEnCours).length + ' EANs distincts\n' +
              '• ' + Object.keys(fournisseurs).length + ' fournisseurs\n' +
              '• Date import : ' + condCommandesMeta.date_import + '\n\n' +
              'Les commandes en cours sont maintenant incluses dans le calcul d\'avancement des engagements.');
      } catch(err) { console.error(err); alert('Erreur : ' + err.message); }
    };
    reader.readAsArrayBuffer(file);
  };
  input.click();
}

// Volume commandé en cours pour un labo sur une liste de sous-marchés
function cmdEnCoursVolume(laboNom, smsIds) {
  var total = 0;
  smsIds.forEach(function(smId) {
    Object.keys(condCommandesEnCours).forEach(function(ean) {
      var m = condMapProduitMarche[ean];
      if (m && m.sous_marche === smId && m.labo === laboNom) {
        total += condCommandesEnCours[ean].qte || 0;
      }
    });
  });
  return total;
}

// ============================================================
// ONGLET PRÉCOMMANDE — Simulation marchés par potentiel
// ============================================================
function precommandeRender() {
  var el = document.getElementById('panel-precommande');
  if (!el) return;

  // Sélecteur labo
  var laboSel = document.getElementById('precom-labo-sel');
  var laboId  = laboSel ? laboSel.value : '';
  var couv    = parseFloat((document.getElementById('precom-couv') || {}).value || 2) || 2;

  // Header
  var labosAvecMC = Object.keys(condLabos).filter(function(id) {
    var mc = JSON.parse(localStorage.getItem('cond_marches_commerciaux') || '{}');
    return mc[id] && Object.keys(mc[id]).length > 0;
  });

  var selHtml = '<select id="precom-labo-sel" onchange="precommandeRender()" style="padding:6px 10px;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:13px;background:var(--surface);color:var(--text)">';
  selHtml += '<option value="">— Choisir un labo —</option>';
  Object.keys(condLabos).forEach(function(id) {
    var l = condLabos[id];
    var mc = JSON.parse(localStorage.getItem('cond_marches_commerciaux') || '{}');
    if (!mc[id] || Object.keys(mc[id]).length === 0) return;
    selHtml += '<option value="' + id + '"' + (id === laboId ? ' selected' : '') + '>' + (l.nom || id) + '</option>';
  });
  selHtml += '</select>';

  // Bandeau état ventes
  var nbVentes = Object.keys(condVentesOspharm).length;
  var metaN = condVentesMeta && condVentesMeta.N;
  var ventesBanner;
  if (nbVentes > 0 && metaN) {
    ventesBanner = '<div style="display:flex;align-items:center;gap:10px;padding:10px 16px;background:#d1fae5;border:1px solid #6ee7b7;border-radius:var(--radius);margin-bottom:16px;font-size:13px">'
      + '<span style="font-size:16px">✅</span>'
      + '<span><strong>' + nbVentes + ' EANs</strong> chargés — période ' + (metaN.debut||'') + ' → ' + (metaN.fin||'') + ' (' + (metaN.nb_jours||'?') + ' j.)</span>'
      + '</div>';
  } else {
    ventesBanner = '<div style="display:flex;align-items:center;gap:10px;padding:10px 16px;background:#fee2e2;border:1px solid #fca5a5;border-radius:var(--radius);margin-bottom:16px;font-size:13px">'
      + '<span style="font-size:16px">⚠️</span>'
      + '<span><strong>Ventes LGPI N non chargées</strong> — les potentiels seront à 0. Importer via <strong>Marchés équivalents → bouton 2</strong>.</span>'
      + '</div>';
  }

  var html = '<div style="padding:20px 0">';
  html += ventesBanner;
  html += '<div style="display:flex;align-items:center;gap:16px;margin-bottom:20px;flex-wrap:wrap">';
  html += '<h2 style="margin:0;font-size:16px;font-weight:600;color:var(--text)">🛒 Simulation Précommande</h2>';
  html += selHtml;
  html += '<label style="font-size:13px;color:var(--text-sec)">Couverture : <input id="precom-couv" type="number" value="' + couv + '" min="1" max="12" step="0.5" onchange="precommandeRender()" style="width:60px;padding:5px 8px;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:13px;text-align:center"> mois</label>';
  html += '</div>';

  if (!laboId) {
    html += '<p style="color:var(--text-ter);font-size:13px">Sélectionne un labo avec des marchés commerciaux configurés.</p>';
    html += '</div>';
    el.innerHTML = html;
    return;
  }

  var labo = condLabos[laboId];
  var mc   = JSON.parse(localStorage.getItem('cond_marches_commerciaux') || '{}');
  var marches = mc[laboId] || {};
  var prods   = labo.produits || [];

  // Enrichir moy depuis condVentesOspharm
  var nbMoisV = (condVentesMeta && condVentesMeta.N && condVentesMeta.N.nb_jours)
                 ? condVentesMeta.N.nb_jours / 30.44 : 12;
  var moyByEan = {};
  var stockByEan = {};
  prods.forEach(function(p) {
    var moy = p.moy || 0;
    var stk = p.stock || 0;
    if (!moy && p.ean && condVentesOspharm[p.ean]) {
      moy = nbMoisV > 0 ? Math.round((condVentesOspharm[p.ean].qtes_n || 0) / nbMoisV * 10) / 10 : 0;
      stk = condVentesOspharm[p.ean].stock || 0;
    }
    moyByEan[p.ean]   = moy;
    stockByEan[p.ean] = stk;
  });
  var colisageByEan = {};
  prods.forEach(function(p) { colisageByEan[p.ean] = p.colisage || 1; });
  // Set des EANs du catalogue de ce labo (pour filtrer les ventes d'autres labos)
  var eansLabo = {};
  prods.forEach(function(p) { eansLabo[p.ean] = true; });
  var paByEan = {};
  prods.forEach(function(p) { paByEan[p.ean] = p.pa_net || p.pu_catalogue || 0; });
  var nomByEan = {};
  prods.forEach(function(p) { nomByEan[p.ean] = p.nom || p.ean; });
  // Enrichir avec libellés depuis tous les labos (EANs hors catalogue actif)
  Object.values(condLabos).forEach(function(l) {
    (l.produits || []).forEach(function(p) {
      if (p.ean && p.nom && (!nomByEan[p.ean] || nomByEan[p.ean] === p.ean)) nomByEan[p.ean] = p.nom;
    });
  });

  // Résumé global
  var totalUnites = 0, totalCA = 0, nbOK = 0, nbKO = 0;

  var tableRows = '';
  var detailHtml = '';

  Object.values(marches).forEach(function(m) {
    var seuil = m.seuil_unite || 0;
    var rem   = m.remise_atteinte || 0;
    var eans  = m.eans || [];

    // Calculer unités commandables et CA par produit
    var lignes = [];
    var totalUnM = 0;
    var totalCAM = 0;

    eans.forEach(function(ean) {
      if (!eansLabo[ean]) return; // exclure EANs hors catalogue de ce labo
      var moy  = moyByEan[ean] || 0;
      var stk  = stockByEan[ean] || 0;
      var col  = colisageByEan[ean] || 1;
      var pa   = paByEan[ean] || 0;
      var nom  = nomByEan[ean] || ean;

      // Potentiel = ventes annuelles (absorption sur 12 mois)
      var vAnn = condVentesOspharm[ean] ? (condVentesOspharm[ean].qtes_n || 0) : Math.round(moy * 12);
      if (vAnn < 1 && moy < 0.1) return; // aucune rotation

      // Quantité à commander = palier de colisage couvrant le besoin couverture
      var besoin = moy * couv;
      var qteNette = Math.max(0, besoin - stk);
      var qte = qteNette > 0 ? Math.ceil(qteNette / col) * col : 0;

      totalUnM += vAnn; // potentiel = ventes annuelles
      if (qte > 0) totalCAM += qte * pa;
      lignes.push({ nom: nom, ean: ean, moy: moy, stk: stk, vAnn: vAnn, qte: qte, pa: pa, ca: qte * pa });
    });

    // Couverture réelle = seuil / (ventes annuelles / 12)
    var moyMensuelle = totalUnM / 12;
    var couvertureReelle = (moyMensuelle > 0 && seuil > 0) ? Math.round(seuil / moyMensuelle * 10) / 10 : null;
    // CA palier = coût d'achat pour atteindre le seuil (PA net moyen × seuil)
    var paMoyenTotal = 0, paMoyenCount = 0;
    lignes.forEach(function(l) { if (l.pa > 0) { paMoyenTotal += l.pa; paMoyenCount++; } });
    var paMoyen = paMoyenCount > 0 ? paMoyenTotal / paMoyenCount : 0;
    var caPalier = seuil > 0 && paMoyen > 0 ? Math.round(seuil * paMoyen) : null;
    var ok = totalUnM >= seuil;
    if (ok) nbOK++; else nbKO++;
    totalUnites += totalUnM;
    totalCA     += totalCAM;

    var pct = seuil > 0 ? Math.min(100, Math.round(totalUnM / seuil * 100)) : 100;
    var barColor = ok ? 'var(--accent)' : (pct >= 60 ? '#f59e0b' : 'var(--danger)');
    var badge = ok
      ? '<span style="background:#d1fae5;color:#065f46;padding:2px 8px;border-radius:20px;font-size:11px;font-weight:600">✅ ATTEIGNABLE</span>'
      : '<span style="background:#fee2e2;color:#991b1b;padding:2px 8px;border-radius:20px;font-size:11px;font-weight:600">❌ ' + (seuil - totalUnM) + ' u. manquantes</span>';

    var mid = m.id || m.label;
    tableRows += '<tr onclick="precommandeToggle(\'' + mid + '\')" style="cursor:pointer;border-bottom:1px solid var(--border)">';
    tableRows += '<td style="padding:10px 12px;font-weight:600;font-size:13px">' + m.label + '</td>';
    tableRows += '<td style="padding:10px 12px;text-align:center;font-size:13px">' + seuil + ' u.</td>';
    tableRows += '<td style="padding:10px 12px">';
    tableRows += '<div style="display:flex;align-items:center;gap:8px">';
    tableRows += '<div style="flex:1;background:var(--surface2);border-radius:4px;height:8px;min-width:80px"><div style="width:' + pct + '%;background:' + barColor + ';height:8px;border-radius:4px"></div></div>';
    tableRows += '<span style="font-size:12px;color:var(--text-sec);white-space:nowrap">' + totalUnM + ' / ' + seuil + ' u.</span>';
    tableRows += '</div></td>';
    tableRows += '<td style="padding:10px 12px;text-align:center;font-weight:600;color:' + (ok ? 'var(--accent-text)' : 'var(--text-sec)') + '">' + (ok ? rem + '%' : '—') + '</td>';
    tableRows += '<td style="padding:10px 12px;text-align:right;font-size:13px">' + Math.round(totalCAM) + ' €</td>';
    tableRows += '<td style="padding:10px 12px;text-align:right;font-size:13px;color:var(--text-sec)">' + (caPalier !== null ? caPalier + ' €' : '—') + '</td>';
    var couvrLabel = couvertureReelle !== null
      ? (couvertureReelle <= 3 ? '<span style="color:var(--accent-text);font-weight:600">' + couvertureReelle + ' mois</span>'
        : couvertureReelle <= 6 ? '<span style="color:#d97706;font-weight:600">' + couvertureReelle + ' mois</span>'
        : '<span style="color:var(--danger);font-weight:600">' + couvertureReelle + ' mois</span>')
      : '<span style="color:var(--text-ter)">—</span>';
    tableRows += '<td style="padding:10px 12px;text-align:center">' + couvrLabel + '</td>';
    tableRows += '<td style="padding:10px 12px">' + badge + '</td>';
    tableRows += '</tr>';

    // Détail produits (masqué par défaut)
    if (lignes.length > 0) {
      detailHtml += '<div id="precom-detail-' + mid + '" style="display:none;margin:-1px 0 8px 0;background:var(--surface2);border:1px solid var(--border);border-top:none;border-radius:0 0 var(--radius) var(--radius);padding:12px 16px">';
      detailHtml += '<table style="width:100%;border-collapse:collapse;font-size:12px">';
      detailHtml += '<thead><tr style="color:var(--text-ter)">';
      detailHtml += '<th style="text-align:left;padding:4px 8px">Produit</th>';
      detailHtml += '<th style="text-align:center;padding:4px 8px">Ventes/an</th>';
      detailHtml += '<th style="text-align:center;padding:4px 8px">Stock</th>';
      detailHtml += '<th style="text-align:center;padding:4px 8px">Qté</th>';
      detailHtml += '<th style="text-align:right;padding:4px 8px">CA HT</th>';
      detailHtml += '</tr></thead><tbody>';
      lignes.forEach(function(l) {
        detailHtml += '<tr style="border-top:1px solid var(--border)">';
        detailHtml += '<td style="padding:5px 8px;max-width:280px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis" title="' + l.nom + '">' + l.nom + '</td>';
        detailHtml += '<td style="text-align:center;padding:5px 8px">' + l.vAnn + '</td>';
        detailHtml += '<td style="text-align:center;padding:5px 8px">' + l.stk + '</td>';
        detailHtml += '<td style="text-align:center;padding:5px 8px;font-weight:600">' + l.qte + '</td>';
        detailHtml += '<td style="text-align:right;padding:5px 8px">' + Math.round(l.ca) + ' €</td>';
        detailHtml += '</tr>';
      });
      detailHtml += '</tbody></table></div>';
    } else {
      detailHtml += '<div id="precom-detail-' + mid + '" style="display:none"></div>';
    }
  });

  // Tableau synthèse
  html += '<div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);overflow:hidden">';
  html += '<div style="padding:12px 16px;background:var(--surface2);border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center">';
  html += '<span style="font-size:13px;font-weight:600">' + labo.nom + ' — S2 2026</span>';
  html += '<span style="font-size:12px;color:var(--text-sec)">' + nbOK + ' marchés atteignables / ' + Object.keys(marches).length + ' | CA total : ' + Math.round(totalCA) + ' €</span>';
  html += '</div>';
  html += '<table style="width:100%;border-collapse:collapse">';
  html += '<thead><tr style="background:var(--surface2);color:var(--text-ter);font-size:11px;text-transform:uppercase">';
  html += '<th style="text-align:left;padding:8px 12px">Marché</th>';
  html += '<th style="text-align:center;padding:8px 12px">Seuil</th>';
  html += '<th style="padding:8px 12px">Potentiel annuel</th>';
  html += '<th style="text-align:center;padding:8px 12px">Remise</th>';
  html += '<th style="text-align:right;padding:8px 12px">CA cmd</th>';
  html += '<th style="text-align:right;padding:8px 12px">CA palier</th>';
  html += '<th style="text-align:center;padding:8px 12px">Écoulement</th>';
  html += '<th style="padding:8px 12px">Statut</th>';
  html += '</tr></thead><tbody>';
  html += tableRows;
  html += '</tbody></table></div>';

  // Détails accordéon
  html += detailHtml;

  html += '<p style="margin-top:12px;font-size:11px;color:var(--text-ter)">⚡ Potentiel = ventes annuelles N (capacité d\'absorption sur 12 mois). Cliquer sur un marché pour le détail. Ventes LGPI N requises.</p>';
  html += '</div>';

  el.innerHTML = html;
}

function precommandeToggle(mid) {
  var d = document.getElementById('precom-detail-' + mid);
  if (d) d.style.display = d.style.display === 'none' ? 'block' : 'none';
}

// ============================================================
// ONGLET CIP/EAN — Table de correspondance anciens/nouveaux codes
// ============================================================
var cipMapData = JSON.parse(localStorage.getItem('cip_map_data') || '[]');

function cipmapSave() {
  try { localStorage.setItem('cip_map_data', JSON.stringify(cipMapData)); } catch(e) {}
}

function cipmapRender() {
  var el = document.getElementById('panel-cipmap');
  if (!el) return;

  var html = '<div style="padding:20px 0">';
  html += '<div style="display:flex;align-items:center;gap:16px;margin-bottom:20px;flex-wrap:wrap">';
  html += '<h2 style="margin:0;font-size:16px;font-weight:600;color:var(--text)">🔄 Table de correspondance CIP / EAN</h2>';
  html += '<button onclick="cipmapAjouter()" style="padding:7px 14px;background:var(--text);color:#fff;border:none;border-radius:var(--radius-sm);font-size:13px;cursor:pointer;font-weight:500">+ Ajouter</button>';
  html += '<button onclick="cipmapExporter()" style="padding:7px 14px;background:transparent;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:13px;cursor:pointer;color:var(--text-sec)">↓ Exporter CSV</button>';
  html += '</div>';

  // Formulaire d'ajout
  html += '<div id="cipmap-form" style="display:none;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius);padding:16px;margin-bottom:16px">';
  html += '<div style="display:flex;gap:12px;flex-wrap:wrap;align-items:flex-end">';
  html += '<div style="display:flex;flex-direction:column;gap:4px"><label style="font-size:11px;color:var(--text-ter);text-transform:uppercase">EAN remplacé (ancien)</label><input id="cipmap-old" type="text" placeholder="ex: 3401234567890" style="padding:7px 10px;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:13px;width:180px;font-family:monospace"></div>';
  html += '<div style="display:flex;flex-direction:column;gap:4px"><label style="font-size:11px;color:var(--text-ter);text-transform:uppercase">EAN remplaçant (nouveau)</label><input id="cipmap-new" type="text" placeholder="ex: 3401234567891" style="padding:7px 10px;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:13px;width:180px;font-family:monospace"></div>';
  html += '<div style="display:flex;flex-direction:column;gap:4px"><label style="font-size:11px;color:var(--text-ter);text-transform:uppercase">Libellé produit</label><input id="cipmap-lib" type="text" placeholder="ex: DOLIPRANE 1000mg cp x8" style="padding:7px 10px;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:13px;width:280px"></div>';
  html += '<div style="display:flex;flex-direction:column;gap:4px"><label style="font-size:11px;color:var(--text-ter);text-transform:uppercase">Labo</label><input id="cipmap-labo" type="text" placeholder="ex: ARKOPHARMA" style="padding:7px 10px;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:13px;width:140px"></div>';
  html += '<button onclick="cipmapConfirmer()" style="padding:7px 16px;background:var(--accent);color:#fff;border:none;border-radius:var(--radius-sm);font-size:13px;cursor:pointer;font-weight:500">Enregistrer</button>';
  html += '<button onclick="cipmapFermerForm()" style="padding:7px 12px;background:transparent;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:13px;cursor:pointer;color:var(--text-sec)">Annuler</button>';
  html += '</div></div>';

  // Barre de recherche
  html += '<div style="margin-bottom:12px"><input id="cipmap-search" type="text" placeholder="Rechercher par EAN ou libellé..." oninput="cipmapFiltrer()" style="width:100%;max-width:400px;padding:8px 12px;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:13px;box-sizing:border-box"></div>';

  // Tableau
  if (cipMapData.length === 0) {
    html += '<p style="color:var(--text-ter);font-size:13px;padding:20px 0">Aucune correspondance enregistrée. Clique sur "+ Ajouter" pour commencer.</p>';
  } else {
    html += '<div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);overflow:hidden">';
    html += '<table style="width:100%;border-collapse:collapse" id="cipmap-table">';
    html += '<thead><tr style="background:var(--surface2);color:var(--text-ter);font-size:11px;text-transform:uppercase">';
    html += '<th style="text-align:left;padding:8px 12px">EAN ancien</th>';
    html += '<th style="text-align:left;padding:8px 12px">EAN nouveau</th>';
    html += '<th style="text-align:left;padding:8px 12px">Libellé</th>';
    html += '<th style="text-align:left;padding:8px 12px">Labo</th>';
    html += '<th style="text-align:left;padding:8px 12px">Date</th>';
    html += '<th style="padding:8px 12px"></th>';
    html += '</tr></thead><tbody id="cipmap-tbody">';
    cipMapData.forEach(function(row, i) {
      html += cipmapLigne(row, i);
    });
    html += '</tbody></table></div>';
    html += '<p style="margin-top:8px;font-size:11px;color:var(--text-ter)">' + cipMapData.length + ' correspondance(s) enregistrée(s)</p>';
  }

  html += '</div>';
  el.innerHTML = html;
}

function cipmapLigne(row, i) {
  return '<tr style="border-bottom:1px solid var(--border)" data-search="' + (row.old+' '+row.new+' '+row.lib+' '+row.labo).toLowerCase() + '">'
    + '<td style="padding:9px 12px;font-family:monospace;font-size:12px;color:var(--text-sec)">' + row.old + '</td>'
    + '<td style="padding:9px 12px;font-family:monospace;font-size:12px;font-weight:600">' + row.new + '</td>'
    + '<td style="padding:9px 12px;font-size:13px">' + (row.lib || '—') + '</td>'
    + '<td style="padding:9px 12px;font-size:12px;color:var(--text-sec)">' + (row.labo || '—') + '</td>'
    + '<td style="padding:9px 12px;font-size:11px;color:var(--text-ter)">' + (row.date || '') + '</td>'
    + '<td style="padding:9px 12px;text-align:right"><button onclick="cipmapSupprimer(' + i + ')" style="padding:3px 8px;font-size:11px;border:1px solid var(--border);border-radius:var(--radius-sm);background:transparent;color:var(--danger);cursor:pointer">✕</button></td>'
    + '</tr>';
}

function cipmapAjouter() {
  document.getElementById('cipmap-form').style.display = 'flex';
  document.getElementById('cipmap-old').focus();
}

function cipmapConfirmer() {
  var oldEan = (document.getElementById('cipmap-old').value || '').trim();
  var newEan = (document.getElementById('cipmap-new').value || '').trim();
  var lib    = (document.getElementById('cipmap-lib').value || '').trim();
  var labo   = (document.getElementById('cipmap-labo').value || '').trim();
  if (!oldEan || !newEan) { alert('EAN ancien et EAN nouveau obligatoires.'); return; }
  var today = new Date().toISOString().slice(0,10);
  cipMapData.unshift({ old: oldEan, new: newEan, lib: lib, labo: labo, date: today });
  cipmapSave();
  cipmapRender();
}

function cipmapSupprimer(i) {
  if (!confirm('Supprimer cette correspondance ?')) return;
  cipMapData.splice(i, 1);
  cipmapSave();
  cipmapRender();
}

function cipmapFiltrer() {
  var q = (document.getElementById('cipmap-search').value || '').toLowerCase();
  var rows = document.querySelectorAll('#cipmap-tbody tr');
  rows.forEach(function(r) {
    r.style.display = (!q || r.dataset.search.indexOf(q) >= 0) ? '' : 'none';
  });
}

function cipmapExporter() {
  if (!cipMapData.length) { alert('Aucune donnée à exporter.'); return; }
  var csv = 'EAN ancien,EAN nouveau,Libellé,Labo,Date\n';
  cipMapData.forEach(function(r) {
    csv += [r.old, r.new, '"'+(r.lib||'').replace(/"/g,'""')+'"', r.labo||'', r.date||''].join(',') + '\n';
  });
  var a = document.createElement('a');
  a.href = 'data:text/csv;charset=utf-8,' + encodeURIComponent(csv);
  a.download = 'cip_map_' + new Date().toISOString().slice(0,10) + '.csv';
  a.click();
}
function cipmapFermerForm() { var f = document.getElementById('cipmap-form'); if(f) f.style.display='none'; }
